void Application::HandleStartListeningEvent()
{
    auto state = GetDeviceState();

    if (state == kDeviceStateActivating)
    {
        SetDeviceState(kDeviceStateIdle);
        return;
    }
    else if (state == kDeviceStateWifiConfiguring)
    {
        audio_service_.EnableAudioTesting(true);
        SetDeviceState(kDeviceStateAudioTesting);
        return;
    }
    else if (state == kDeviceStateAudioTesting)
    {
        audio_service_.EnableAudioTesting(false);
        SetDeviceState(kDeviceStateWifiConfiguring);
        return;
    }

    if (!protocol_)
    {
        ESP_LOGE(TAG, "Protocol not initialized");
        return;
    }

    if (state == kDeviceStateIdle)
    {
        if (!protocol_->IsAudioChannelOpened())
        {
            SetDeviceState(kDeviceStateConnecting);
            if (!protocol_->OpenAudioChannel())
            {
                return;
            }
        }

        SetListeningMode(kListeningModeManualStop);

        // Enable voice processing for listening
        audio_service_.EnableVoiceProcessing(true);
        audio_service_.EnableWakeWordDetection(false); // Disable wake word during manual listening

        // Update display for listening state
        auto display = Board::GetInstance().GetDisplay();
        display->SetStatus(Lang::Strings::LISTENING);
        display->SetEmotion("mic_listen");
        display->SetChatMessage("system", "");

        // Send start listening command to protocol
        protocol_->SendStartListening();
    }
    else if (state == kDeviceStateSpeaking)
    {
        AbortSpeaking(kAbortReasonNone);

        // Wait a bit for the abort to process
        vTaskDelay(pdMS_TO_TICKS(100));

        if (!protocol_->IsAudioChannelOpened())
        {
            SetDeviceState(kDeviceStateConnecting);
            if (!protocol_->OpenAudioChannel())
            {
                return;
            }
        }

        SetListeningMode(kListeningModeManualStop);

        // Enable voice processing for listening
        audio_service_.EnableVoiceProcessing(true);
        audio_service_.EnableWakeWordDetection(false); // Disable wake word during manual listening

        // Update display for listening state
        auto display = Board::GetInstance().GetDisplay();
        display->SetStatus(Lang::Strings::LISTENING);
        display->SetEmotion("mic_listen");
        display->SetChatMessage("system", "");

        // Send start listening command to protocol
        protocol_->SendStartListening();
    }
}

