bool Assets::InitializePartition() {
    // Step 1: Verify partition existence and minimum size requirements
    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");
    if (partition_ == nullptr) {
        ESP_LOGE(TAG, "Assets partition not found");
        partition_valid_ = false;
        return false;
    }

    if (partition_->size < sizeof(uint32_t)) {
        ESP_LOGE(TAG, "Assets partition too small");
        partition_valid_ = false;
        return false;
    }

    partition_valid_ = true;

    // Step 2: Map the partition into memory for direct access
    if (mmap_handle_ != 0) {
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
    }

    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, SPI_FLASH_MMAP_DATA, 
                                       (const void**)&mmap_root_, &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    // Step 3: Perform checksum validation on the partition data
    if (partition_->size < sizeof(uint32_t)) {
        ESP_LOGE(TAG, "Assets partition too small for checksum");
        return false;
    }

    // Read stored checksum (first 4 bytes)
    uint32_t stored_checksum = *((uint32_t*)mmap_root_);

    // Calculate checksum of the rest of the data
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_ + sizeof(uint32_t), 
                                                    partition_->size - sizeof(uint32_t));

    if (stored_checksum != calculated_checksum) {
        ESP_LOGE(TAG, "Checksum mismatch: stored=0x%04X, calculated=0x%04X", 
                 stored_checksum, calculated_checksum);
        checksum_valid_ = false;
        return false;
    }

    checksum_valid_ = true;

    // Step 4: Build in-memory index of assets with size and offset metadata
    assets_.clear();

    // Start reading asset entries after the checksum (4 bytes) and skip the first "ZZ" marker
    size_t offset = sizeof(uint32_t);
    const size_t min_asset_size = sizeof("ZZ") - 1 + sizeof(mmap_assets_table);

    while (offset + min_asset_size <= partition_->size) {
        const char* current_ptr = mmap_root_ + offset;

        // Check for asset magic "ZZ"
        if (current_ptr[0] != 'Z' || current_ptr[1] != 'Z') {
            // If we don't find the magic at the expected position, move forward by one byte
            offset++;
            continue;
        }

        // Skip the "ZZ" magic
        offset += 2;
        current_ptr += 2;

        // Check if we have enough space for the asset table entry
        if (offset + sizeof(mmap_assets_table) > partition_->size) {
            break;
        }

        // Read asset metadata
        const mmap_assets_table* asset_entry = (const mmap_assets_table*)current_ptr;

        // Validate asset entry
        if (asset_entry->asset_size == 0 || 
            offset + sizeof(mmap_assets_table) + asset_entry->asset_size > partition_->size) {
            ESP_LOGW(TAG, "Invalid asset entry detected, stopping asset parsing");
            break;
        }

        // Add asset to the index
        Asset asset;
        asset.size = asset_entry->asset_size;
        asset.offset = offset + sizeof(mmap_assets_table); // Point to actual asset data

        std::string asset_name(asset_entry->asset_name);
        assets_[asset_name] = asset;

        ESP_LOGD(TAG, "Found asset: %s, size: %u, offset: %u", 
                 asset_name.c_str(), asset.size, asset.offset);

        // Move to next potential asset (skip metadata + asset data)
        offset += sizeof(mmap_assets_table) + asset_entry->asset_size;
    }

    ESP_LOGI(TAG, "Assets partition initialized successfully with %d assets", assets_.size());
    return true;
}

