    ESP_LOGI(TAG, "Starting download from %s", url.c_str());

    // Initialize HTTP client
    esp_http_client_config_t config = {};
    config.url = url.c_str();
    config.timeout_ms = 30000;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    // Open HTTP connection
    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Get content length
    int content_length = esp_http_client_fetch_headers(client);
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Invalid content length: %d", content_length);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Validate content size against partition size
    if ((size_t)content_length > partition_->size) {
        ESP_LOGE(TAG, "Content size (%d bytes) exceeds partition size (%d bytes)", content_length, partition_->size);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    ESP_LOGI(TAG, "Content length: %d bytes", content_length);

    // Allocate buffer for downloading
    const size_t buffer_size = 4096;
    uint8_t* buffer = (uint8_t*)malloc(buffer_size);
    if (!buffer) {
        ESP_LOGE(TAG, "Failed to allocate download buffer");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Erase flash memory sectors
    ESP_LOGI(TAG, "Erasing flash memory...");
    size_t sector_size = SPI_FLASH_SEC_SIZE;
    size_t sectors_to_erase = (content_length + sector_size - 1) / sector_size;

    for (size_t i = 0; i < sectors_to_erase; i++) {
        err = esp_partition_erase_range(partition_, i * sector_size, sector_size);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to erase sector %d: %s", i, esp_err_to_name(err));
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }
    }

    // Download and write data
    size_t total_written = 0;
    int64_t last_progress_time = esp_timer_get_time();
    size_t last_progress_bytes = 0;
    int last_progress_percent = -1;

    ESP_LOGI(TAG, "Downloading and writing data...");

    while (total_written < (size_t)content_length) {
        int bytes_read = esp_http_client_read(client, (char*)buffer, buffer_size);
        if (bytes_read < 0) {
            ESP_LOGE(TAG, "Failed to read HTTP data");
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        if (bytes_read == 0) {
            break; // End of stream
        }

        // Write to flash
        err = esp_partition_write(partition_, total_written, buffer, bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to flash at offset %d: %s", total_written, esp_err_to_name(err));
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        total_written += bytes_read;

        // Update progress
        int64_t current_time = esp_timer_get_time();
        if (current_time - last_progress_time >= 1000000 || total_written >= (size_t)content_length) { // Every second or at completion
            int progress_percent = (total_written * 100) / content_length;
            size_t bytes_since_last = total_written - last_progress_bytes;
            size_t time_elapsed_sec = (current_time - last_progress_time) / 1000000;
            size_t current_speed = time_elapsed_sec > 0 ? bytes_since_last / time_elapsed_sec : 0;

            if (progress_percent != last_progress_percent && progress_callback) {
                progress_callback(progress_percent, current_speed);
                last_progress_percent = progress_percent;
            }

            last_progress_time = current_time;
            last_progress_bytes = total_written;

            ESP_LOGD(TAG, "Download progress: %d%% (%d/%d bytes, %d B/s)", 
                     progress_percent, total_written, content_length, current_speed);
        }
    }

    free(buffer);
    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    if (total_written != (size_t)content_length) {
        ESP_LOGE(TAG, "Incomplete download: expected %d bytes, got %d bytes", content_length, total_written);
        return false;
    }

    ESP_LOGI(TAG, "Download completed successfully: %d bytes", total_written);

    // Verify written data by remapping the partition
    if (mmap_handle_ != 0) {
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
    }

    const void* mapped_data;
    err = esp_partition_mmap(partition_, 0, partition_->size, ESP_PARTITION_MMAP_DATA, &mapped_data, &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to remap partition: %s", esp_err_to_name(err));
        return false;
    }
    mmap_root_ = (const char*)mapped_data;

    // Reinitialize assets after download
    InitializePartition();

    return true;
}

