bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const {
    // Self-transitions are always valid
    if (from == to) {
        return true;
    }

    // Transitioning to invalid state is not allowed
    if (to == kDeviceStateInvalid) {
        return false;
    }

    // Transitioning to fatal_error is generally allowed unless already there
    if (to == kDeviceStateFatalError && from != kDeviceStateFatalError) {
        return true;
    }

    switch (from) {
        case kDeviceStateUnknown:
            return to == kDeviceStateStarting;

        case kDeviceStateStarting:
            return to == kDeviceStateWifiConfiguring || to == kDeviceStateIdle;

        case kDeviceStateWifiConfiguring:
            return to == kDeviceStateIdle;

        case kDeviceStateIdle:
            return to == kDeviceStateConnecting ||
                   to == kDeviceStateListening ||
                   to == kDeviceStateSpeaking ||
                   to == kDeviceStateAudioTesting ||
                   to == kDeviceStateUpgrading ||
                   to == kDeviceStateActivating;

        case kDeviceStateConnecting:
            return to == kDeviceStateListening || to == kDeviceStateIdle;

        case kDeviceStateListening:
            return to == kDeviceStateSpeaking || to == kDeviceStateIdle;

        case kDeviceStateSpeaking:
            return to == kDeviceStateListening || to == kDeviceStateIdle;

        case kDeviceStateAudioTesting:
            return to == kDeviceStateIdle;

        case kDeviceStateUpgrading:
            return to == kDeviceStateIdle;

        case kDeviceStateActivating:
            return to == kDeviceStateIdle;

        case kDeviceStateFatalError:
            // Fatal error should prevent further transitions except reset/restart logic outside scope here
            return false;

        default:
            // Unknown or unexpected 'from' state
            return false;
    }
}

