void McpServer::ParseMessage(const cJSON* json) {
    // Validate JSON-RPC 2.0 message structure
    if (!cJSON_IsObject(json)) {
        ESP_LOGE(TAG, "Invalid JSON-RPC message: not an object");
        return;
    }

    // Check jsonrpc version
    auto jsonrpc = cJSON_GetObjectItem(json, "jsonrpc");
    if (!cJSON_IsString(jsonrpc) || strcmp(jsonrpc->valuestring, "2.0") != 0) {
        ESP_LOGE(TAG, "Invalid JSON-RPC version");
        return;
    }

    // Get message ID
    auto id_item = cJSON_GetObjectItem(json, "id");
    if (!id_item) {
        ESP_LOGE(TAG, "Missing ID in JSON-RPC message");
        return;
    }
    int id = id_item->valueint;

    // Get method
    auto method = cJSON_GetObjectItem(json, "method");
    if (!cJSON_IsString(method)) {
        // This might be a response, not a request
        auto result = cJSON_GetObjectItem(json, "result");
        auto error = cJSON_GetObjectItem(json, "error");
        if (result || error) {
            // This is a response message, ignore it
            return;
        }
        ESP_LOGE(TAG, "Missing method in JSON-RPC request");
        ReplyError(id, "Missing method in JSON-RPC request");
        return;
    }

    std::string method_name = method->valuestring;

    // Route based on method name
    if (method_name == "initialize") {
        // Handle initialize method
        auto params = cJSON_GetObjectItem(json, "params");
        if (cJSON_IsObject(params)) {
            auto capabilities = cJSON_GetObjectItem(params, "capabilities");
            if (cJSON_IsObject(capabilities)) {
                ParseCapabilities(capabilities);
            }
        }

        // Send initialization response
        cJSON* response = cJSON_CreateObject();
        cJSON_AddStringToObject(response, "protocolVersion", "2024-11-05");

        cJSON* capabilities = cJSON_CreateObject();
        cJSON_AddItemToObject(response, "capabilities", capabilities);

        char* response_str = cJSON_PrintUnformatted(response);
        std::string response_string(response_str);
        free(response_str);
        cJSON_Delete(response);

        ReplyResult(id, response_string);
    }
    else if (method_name == "tools/list") {
        // Handle tools/list method
        std::string cursor = "";
        bool list_user_only_tools = false;

        auto params = cJSON_GetObjectItem(json, "params");
        if (cJSON_IsObject(params)) {
            auto cursor_item = cJSON_GetObjectItem(params, "cursor");
            if (cJSON_IsString(cursor_item)) {
                cursor = cursor_item->valuestring;
            }

            auto user_only_item = cJSON_GetObjectItem(params, "user_only");
            if (cJSON_IsBool(user_only_item)) {
                list_user_only_tools = cJSON_IsTrue(user_only_item);
            }
        }

        GetToolsList(id, cursor, list_user_only_tools);
    }
    else if (method_name == "tools/call") {
        // Handle tools/call method
        auto params = cJSON_GetObjectItem(json, "params");
        if (!cJSON_IsObject(params)) {
            ESP_LOGE(TAG, "Missing params in tools/call");
            ReplyError(id, "Missing params in tools/call");
            return;
        }

        auto name_item = cJSON_GetObjectItem(params, "name");
        if (!cJSON_IsString(name_item)) {
            ESP_LOGE(TAG, "Missing tool name in tools/call");
            ReplyError(id, "Missing tool name in tools/call");
            return;
        }

        std::string tool_name = name_item->valuestring;
        auto arguments = cJSON_GetObjectItem(params, "arguments");

        DoToolCall(id, tool_name, arguments);
    }
    else {
        // Unknown method
        ESP_LOGE(TAG, "Unknown method: %s", method_name.c_str());
        ReplyError(id, "Unknown method: " + method_name);
    }
}

