void McpServer::GetToolsList(int id, const std::string& cursor, bool list_user_only_tools) {
    constexpr size_t MAX_TOOLS_PER_PAGE = 10;
    size_t cursor_pos = 0;

    // Parse cursor if provided
    if (!cursor.empty()) {
        try {
            cursor_pos = std::stoull(cursor);
        } catch (...) {
            ReplyError(id, "Invalid cursor format");
            return;
        }
    }

    // Validate cursor position
    if (cursor_pos > tools_.size()) {
        ReplyError(id, "Invalid cursor position");
        return;
    }

    // Filter tools based on user permissions
    std::vector<const McpTool*> filtered_tools;
    for (size_t i = cursor_pos; i < tools_.size(); ++i) {
        const McpTool* tool = tools_[i];
        // If listing user tools only, skip non-user tools
        if (list_user_only_tools && !tool->user_only()) {
            continue;
        }
        // Regular users cannot access user-only tools
        if (!list_user_only_tools && tool->user_only()) {
            continue;
        }
        filtered_tools.push_back(tool);

        // Limit the number of tools per page
        if (filtered_tools.size() >= MAX_TOOLS_PER_PAGE) {
            break;
        }
    }

    // Build JSON response
    std::string result = "{";

    // Add tools array
    result += "\"tools\":[";
    for (size_t i = 0; i < filtered_tools.size(); ++i) {
        if (i > 0) {
            result += ",";
        }

        const McpTool* tool = filtered_tools[i];
        result += "{";
        result += "\"name\":\"" + tool->name() + "\",";
        result += "\"description\":\"" + tool->description() + "\"";

        // Add input schema if properties exist
        if (!tool->properties().empty()) {
            result += ",\"inputSchema\":{";
            result += "\"type\":\"object\",";
            result += "\"properties\":{";

            bool first_prop = true;
            for (const auto& prop : tool->properties()) {
                if (!first_prop) {
                    result += ",";
                }

                result += "\"" + prop.name() + "\":{";

                switch (prop.type()) {
                    case kPropertyTypeString:
                        result += "\"type\":\"string\"";
                        break;
                    case kPropertyTypeInteger:
                        result += "\"type\":\"integer\"";
                        break;
                    case kPropertyTypeBoolean:
                        result += "\"type\":\"boolean\"";
                        break;
                    default:
                        result += "\"type\":\"string\"";
                        break;
                }

                if (prop.has_default_value()) {
                    result += ",\"default\":";
                    switch (prop.type()) {
                        case kPropertyTypeString:
                            result += "\"" + prop.default_value<std::string>() + "\"";
                            break;
                        case kPropertyTypeInteger:
                            result += std::to_string(prop.default_value<int>());
                            break;
                        case kPropertyTypeBoolean:
                            result += prop.default_value<bool>() ? "true" : "false";
                            break;
                        default:
                            break;
                    }
                }

                // Add range constraints for integers
                if (prop.type() == kPropertyTypeInteger) {
                    result += ",\"minimum\":" + std::to_string(prop.min_value());
                    result += ",\"maximum\":" + std::to_string(prop.max_value());
                }

                result += "}";
                first_prop = false;
            }

            result += "}";

            // Add required fields
            result += ",\"required\":[";
            bool first_required = true;
            for (const auto& prop : tool->properties()) {
                if (!prop.has_default_value()) {
                    if (!first_required) {
                        result += ",";
                    }
                    result += "\"" + prop.name() + "\"";
                    first_required = false;
                }
            }
            result += "]";

            result += "}";
        }

        result += "}";
    }
    result += "]";

    // Add next cursor if there are more tools
    if (cursor_pos + MAX_TOOLS_PER_PAGE < tools_.size()) {
        result += ",\"nextCursor\":\"" + std::to_string(cursor_pos + MAX_TOOLS_PER_PAGE) + "\"";
    }

    result += "}";

    // Check payload size
    constexpr size_t MAX_PAYLOAD_SIZE = 16384; // 16KB limit
    if (result.size() > MAX_PAYLOAD_SIZE) {
        ReplyError(id, "Tool list exceeds maximum payload size");
        return;
    }

    ReplyResult(id, result);
}

