void McpServer::DoToolCall(int id, const std::string& tool_name, const cJSON* tool_arguments) {
    // Step 1: Validate the tool name and retrieve tool metadata
    McpTool* tool = nullptr;
    for (auto t : tools_) {
        if (t->name() == tool_name) {
            tool = t;
            break;
        }
    }

    if (tool == nullptr) {
        ESP_LOGE(TAG, "Tool not found: %s", tool_name.c_str());
        ReplyError(id, "Tool not found: " + tool_name);
        return;
    }

    // Step 2 & 3: Parse and type-check provided arguments, verify required parameters
    PropertyList parsed_properties;
    try {
        const auto& expected_properties = tool->properties();

        // Initialize with default values
        for (const auto& prop : expected_properties) {
            parsed_properties[prop.name()] = prop;
        }

        // Parse provided arguments
        if (tool_arguments != nullptr) {
            int array_size = cJSON_GetArraySize(tool_arguments);
            for (int i = 0; i < array_size; i++) {
                cJSON* item = cJSON_GetArrayItem(tool_arguments, i);
                if (item != nullptr && item->string != nullptr) {
                    std::string arg_name = item->string;

                    // Check if this argument is expected
                    auto prop_it = std::find_if(expected_properties.begin(), expected_properties.end(),
                                              [&arg_name](const Property& p) { return p.name() == arg_name; });

                    if (prop_it != expected_properties.end()) {
                        // Type checking and conversion
                        const Property& expected_prop = *prop_it;
                        Property parsed_prop = expected_prop;

                        switch (expected_prop.type()) {
                            case kPropertyTypeString:
                                if (cJSON_IsString(item)) {
                                    parsed_prop.set_value<std::string>(std::string(item->valuestring));
                                } else {
                                    throw std::runtime_error("Argument '" + arg_name + "' must be a string");
                                }
                                break;

                            case kPropertyTypeInteger:
                                if (cJSON_IsNumber(item)) {
                                    int value = item->valueint;
                                    // Check range constraints
                                    if (expected_prop.has_min() && value < expected_prop.min()) {
                                        throw std::runtime_error("Argument '" + arg_name + "' must be >= " + std::to_string(expected_prop.min()));
                                    }
                                    if (expected_prop.has_max() && value > expected_prop.max()) {
                                        throw std::runtime_error("Argument '" + arg_name + "' must be <= " + std::to_string(expected_prop.max()));
                                    }
                                    parsed_prop.set_value<int>(value);
                                } else {
                                    throw std::runtime_error("Argument '" + arg_name + "' must be an integer");
                                }
                                break;

                            case kPropertyTypeBoolean:
                                if (cJSON_IsBool(item)) {
                                    parsed_prop.set_value<bool>(item->valueint != 0);
                                } else {
                                    throw std::runtime_error("Argument '" + arg_name + "' must be a boolean");
                                }
                                break;

                            default:
                                throw std::runtime_error("Unsupported property type for argument '" + arg_name + "'");
                        }

                        parsed_properties[arg_name] = parsed_prop;
                    } else {
                        ESP_LOGW(TAG, "Unknown argument '%s' for tool '%s'", arg_name.c_str(), tool_name.c_str());
                    }
                }
            }
        }

        // Validate all required parameters are present
        for (const auto& prop : expected_properties) {
            bool found = false;
            for (const auto& parsed_prop : parsed_properties) {
                if (parsed_prop.name() == prop.name()) {
                    found = true;
                    break;
                }
            }
            if (!found && !prop.optional()) {
                throw std::runtime_error("Missing required argument: " + prop.name());
            }
        }
    } catch (const std::exception& e) {
        ESP_LOGE(TAG, "Argument validation failed for tool %s: %s", tool_name.c_str(), e.what());
        ReplyError(id, "Argument validation failed: " + std::string(e.what()));
        return;
    }

    // Step 4: Schedule tool execution on the main application thread
    auto& app = Application::GetInstance();
    auto tool_callback = tool->callback();

    app.Schedule([this, id, tool_callback, parsed_properties]() {
        // Step 5: Execute the tool and capture result or error
        try {
            ReturnValue result = tool_callback(parsed_properties);

            // Step 6: Send structured response
            if (result.type() == ReturnValue::kTypeBool) {
                bool bool_result = result.value<bool>();
                ReplyResult(id, bool_result ? "true" : "false");
            } else if (result.type() == ReturnValue::kTypeCjson) {
                char* json_str = cJSON_PrintUnformatted(result.value<cJSON*>());
                if (json_str != nullptr) {
                    std::string result_str(json_str);
                    free(json_str);
                    ReplyResult(id, result_str);
                } else {
                    ReplyError(id, "Failed to serialize tool result");
                }
            } else if (result.type() == ReturnValue::kTypeString) {
                std::string str_result = result.value<std::string>();
                ReplyResult(id, "\"" + str_result + "\"");
            } else {
                ReplyResult(id, "null");
            }
        } catch (const std::exception& e) {
            ESP_LOGE(TAG, "Tool execution failed: %s", e.what());
            ReplyError(id, "Tool execution failed: " + std::string(e.what()));
        } catch (...) {
            ESP_LOGE(TAG, "Tool execution failed with unknown error");
            ReplyError(id, "Tool execution failed with unknown error");
        }
    });
}

