/*
 * Specification: https://ccnphfhqs21z.feishu.cn/wiki/FjW6wZmisimNBBkov6OcmfvknVd
 */
esp_err_t Ota::CheckVersion()
{
    std::string url = GetCheckVersionUrl();
    if (url.empty()) {
        ESP_LOGE(TAG, "OTA URL is empty");
        return ESP_ERR_INVALID_ARG;
    }

    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP client");
        return ESP_FAIL;
    }

    // Prepare request data
    cJSON *root = cJSON_CreateObject();
    if (!root) {
        ESP_LOGE(TAG, "Failed to create JSON object");
        return ESP_ERR_NO_MEM;
    }

    // Add current version info
    const esp_app_desc_t *app_desc = esp_app_get_description();
    cJSON_AddStringToObject(root, "version", app_desc->version);

    // Add device information
    cJSON_AddStringToObject(root, "device_id", SystemInfo::GetMacAddress().c_str());

    // Add activation data if needed
    if (has_activation_challenge_) {
        cJSON_AddStringToObject(root, "activation_challenge", activation_challenge_.c_str());
    }

    char *json_string = cJSON_PrintUnformatted(root);
    if (!json_string) {
        cJSON_Delete(root);
        ESP_LOGE(TAG, "Failed to print JSON");
        return ESP_ERR_NO_MEM;
    }

    std::string data(json_string);
    cJSON_free(json_string);
    cJSON_Delete(root);

    http->SetContent(std::move(data));

    if (!http->Open("POST", url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", url.c_str());
        return ESP_FAIL;
    }

    int status_code = http->GetStatusCode();
    if (status_code != 200) {
        ESP_LOGE(TAG, "HTTP request failed with status code: %d", status_code);
        std::string response_body = http->ReadAll();
        ESP_LOGE(TAG, "Response body: %s", response_body.c_str());
        return ESP_FAIL;
    }

    std::string response = http->ReadAll();
    if (response.empty()) {
        ESP_LOGE(TAG, "Empty response from server");
        return ESP_FAIL;
    }

    // Parse JSON response
    cJSON *response_json = cJSON_Parse(response.c_str());
    if (!response_json) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Extract firmware version
    cJSON *version_item = cJSON_GetObjectItemCaseSensitive(response_json, "version");
    if (version_item && cJSON_IsString(version_item)) {
        std::string new_version = version_item->valuestring;
        const char *current_version = app_desc->version;

        if (IsNewVersionAvailable(current_version, new_version)) {
            ESP_LOGI(TAG, "New firmware version available: %s (current: %s)", 
                     new_version.c_str(), current_version);

            cJSON *firmware_url_item = cJSON_GetObjectItemCaseSensitive(response_json, "firmware_url");
            if (firmware_url_item && cJSON_IsString(firmware_url_item)) {
                firmware_url_ = firmware_url_item->valuestring;
                has_new_version_ = true;
            }
        } else {
            ESP_LOGI(TAG, "Device is up to date (version: %s)", current_version);
            has_new_version_ = false;
        }
    }

    // Handle activation challenge
    cJSON *activation_challenge_item = cJSON_GetObjectItemCaseSensitive(response_json, "activation_challenge");
    if (activation_challenge_item && cJSON_IsString(activation_challenge_item)) {
        activation_challenge_ = activation_challenge_item->valuestring;
        has_activation_challenge_ = true;
        ESP_LOGI(TAG, "Received activation challenge");
    } else {
        has_activation_challenge_ = false;
    }

    // Handle activation code
    cJSON *activation_code_item = cJSON_GetObjectItemCaseSensitive(response_json, "activation_code");
    if (activation_code_item && cJSON_IsString(activation_code_item)) {
        activation_code_ = activation_code_item->valuestring;
        has_activation_code_ = true;
        ESP_LOGI(TAG, "Received activation code");

        cJSON *activation_message_item = cJSON_GetObjectItemCaseSensitive(response_json, "activation_message");
        if (activation_message_item && cJSON_IsString(activation_message_item)) {
            activation_message_ = activation_message_item->valuestring;
        }
    } else {
        has_activation_code_ = false;
    }

    // Handle MQTT configuration updates
    cJSON *mqtt_config_item = cJSON_GetObjectItemCaseSensitive(response_json, "mqtt");
    if (mqtt_config_item && cJSON_IsObject(mqtt_config_item)) {
        cJSON *broker_item = cJSON_GetObjectItemCaseSensitive(mqtt_config_item, "broker");
        cJSON *port_item = cJSON_GetObjectItemCaseSensitive(mqtt_config_item, "port");
        cJSON *username_item = cJSON_GetObjectItemCaseSensitive(mqtt_config_item, "username");
        cJSON *password_item = cJSON_GetObjectItemCaseSensitive(mqtt_config_item, "password");
        cJSON *client_id_item = cJSON_GetObjectItemCaseSensitive(mqtt_config_item, "client_id");

        Settings mqtt_settings("mqtt", false);

        if (broker_item && cJSON_IsString(broker_item)) {
            mqtt_settings.SetString("broker", broker_item->valuestring);
        }
        if (port_item && cJSON_IsNumber(port_item)) {
            mqtt_settings.SetInt("port", port_item->valueint);
        }
        if (username_item && cJSON_IsString(username_item)) {
            mqtt_settings.SetString("username", username_item->valuestring);
        }
        if (password_item && cJSON_IsString(password_item)) {
            mqtt_settings.SetString("password", password_item->valuestring);
        }
        if (client_id_item && cJSON_IsString(client_id_item)) {
            mqtt_settings.SetString("client_id", client_id_item->valuestring);
        }

        mqtt_settings.Save();
        ESP_LOGI(TAG, "MQTT configuration updated");
    }

    // Handle other configuration updates
    cJSON *config_item = cJSON_GetObjectItemCaseSensitive(response_json, "config");
    if (config_item && cJSON_IsObject(config_item)) {
        Settings general_settings("general", false);
        cJSON *current = nullptr;
        cJSON_ArrayForEach(current, config_item) {
            if (cJSON_IsString(current)) {
                general_settings.SetString(current->string, current->valuestring);
            } else if (cJSON_IsNumber(current)) {
                general_settings.SetInt(current->string, current->valueint);
            } else if (cJSON_IsBool(current)) {
                general_settings.SetBool(current->string, cJSON_IsTrue(current));
            }
        }
        general_settings.Save();
        ESP_LOGI(TAG, "General configuration updated");
    }

    cJSON_Delete(response_json);
    return ESP_OK;
}

