std::string Ota::GetActivationPayload()
{
    // Return empty JSON object if no serial number is available
    if (!has_serial_number_) {
        return "{}";
    }

    // Check if we have a challenge
    if (!has_activation_challenge_) {
        return "{}";
    }

    cJSON *root = cJSON_CreateObject();
    if (root == NULL) {
        return "{}";
    }

    // Add serial number to payload
    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());

    // Add challenge to payload
    cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());

    // Compute HMAC-SHA256 signature
    std::string signature;
#ifdef SOC_HMAC_SUPPORTED
    uint8_t hmac_result[32];
    size_t hmac_len = 0;

    // Create data to sign: serial_number + challenge
    std::string data_to_sign = serial_number_ + activation_challenge_;

    // Use hardware HMAC with key 0 (typically the most secure option)
    esp_err_t ret = esp_hmac_calculate(HMAC_KEY0, data_to_sign.c_str(), data_to_sign.length(), hmac_result);
    if (ret == ESP_OK) {
        // Convert binary HMAC to hex string
        char hex_string[65]; // 32 bytes * 2 chars per byte + null terminator
        for (int i = 0; i < 32; i++) {
            sprintf(&hex_string[i * 2], "%02x", hmac_result[i]);
        }
        hex_string[64] = '\0';
        signature = std::string(hex_string);
    }
#endif

    // Add signature to payload (empty if HMAC failed or not supported)
    cJSON_AddStringToObject(root, "signature", signature.c_str());

    // Convert to JSON string
    char *json_string = cJSON_PrintUnformatted(root);
    std::string result;
    if (json_string != NULL) {
        result = std::string(json_string);
        free(json_string);
    } else {
        result = "{}";
    }

    cJSON_Delete(root);
    return result;
}

