esp_err_t Ota::Activate()
{
    // Construct the activation URL
    std::string base_url = GetCheckVersionUrl();
    // Remove any query parameters or path components and append /activate
    size_t query_pos = base_url.find('?');
    if (query_pos != std::string::npos) {
        base_url = base_url.substr(0, query_pos);
    }

    // Ensure URL ends with / and add activate endpoint
    if (!base_url.empty() && base_url.back() != '/') {
        base_url += "/";
    }
    std::string activation_url = base_url + "activate";

    ESP_LOGI(TAG, "Activating firmware version %s", current_version_.c_str());
    ESP_LOGI(TAG, "Activation URL: %s", activation_url.c_str());

    // Setup HTTP connection
    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP client");
        return ESP_FAIL;
    }

    // Prepare payload
    std::string payload = GetActivationPayload();

    // Set HTTP content
    http->SetContent(payload);

    // Open HTTP connection with POST method
    if (!http->Open("POST", activation_url)) {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for activation, code=0x%x", last_error);
        return last_error;
    }

    // Get HTTP status code
    int status_code = http->GetStatusCode();
    ESP_LOGI(TAG, "Activation response status code: %d", status_code);

    // Read response data
    std::string response_data = http->ReadAll();
    http->Close();

    // Handle different status codes
    switch (status_code) {
        case 200:
            ESP_LOGI(TAG, "Activation successful");
            // Parse response if needed
            if (!response_data.empty()) {
                cJSON *root = cJSON_Parse(response_data.c_str());
                if (root) {
                    cJSON *result = cJSON_GetObjectItem(root, "result");
                    if (cJSON_IsString(result)) {
                        ESP_LOGI(TAG, "Activation result: %s", result->valuestring);
                    }
                    cJSON_Delete(root);
                }
            }
            return ESP_OK;

        case 202:
            ESP_LOGI(TAG, "Activation accepted, pending confirmation");
            return ESP_ERR_NOT_FINISHED;

        case 400:
            ESP_LOGE(TAG, "Bad request in activation: %s", response_data.c_str());
            return ESP_ERR_INVALID_ARG;

        case 401:
            ESP_LOGE(TAG, "Unauthorized activation attempt");
            return ESP_ERR_INVALID_STATE;

        case 404:
            ESP_LOGE(TAG, "Activation endpoint not found");
            return ESP_ERR_NOT_FOUND;

        case 408:
            ESP_LOGE(TAG, "Activation request timeout");
            return ESP_ERR_TIMEOUT;

        case 422:
            ESP_LOGE(TAG, "Activation data invalid");
            return ESP_ERR_INVALID_RESPONSE;

        case 500:
            ESP_LOGE(TAG, "Server error during activation");
            return ESP_FAIL;

        default:
            ESP_LOGE(TAG, "Unexpected status code during activation: %d", status_code);
            if (status_code >= 400 && status_code < 500) {
                return ESP_ERR_INVALID_RESPONSE;
            } else if (status_code >= 500) {
                return ESP_FAIL;
            }
            return ESP_ERR_INVALID_STATE;
    }
}

