esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait) {
    // Define constants
    const size_t TASK_BUFFER_SIZE = 32;
    TaskStatus_t pxTaskStatusArrayInitial[TASK_BUFFER_SIZE];
    TaskStatus_t pxTaskStatusArrayFinal[TASK_BUFFER_SIZE];
    uint32_t ulTotalRunTimeInitial, ulTotalRunTimeFinal;

    // Step 1: Capture initial task stats
    UBaseType_t uxArraySizeInitial = uxTaskGetSystemState(pxTaskStatusArrayInitial, TASK_BUFFER_SIZE, &ulTotalRunTimeInitial);
    if (uxArraySizeInitial == 0) {
        ESP_LOGE(TAG, "Failed to retrieve initial task state.");
        return ESP_FAIL;
    }

    // Step 2: Delay for the specified period
    vTaskDelay(xTicksToWait);

    // Step 3: Capture final task stats
    UBaseType_t uxArraySizeFinal = uxTaskGetSystemState(pxTaskStatusArrayFinal, TASK_BUFFER_SIZE, &ulTotalRunTimeFinal);
    if (uxArraySizeFinal == 0) {
        ESP_LOGE(TAG, "Failed to retrieve final task state.");
        return ESP_FAIL;
    }

    // Step 4: Calculate elapsed total run time in ticks
    uint32_t ulTotalElapsedTime = ulTotalRunTimeFinal - ulTotalRunTimeInitial;
    if (ulTotalElapsedTime == 0) {
        ESP_LOGW(TAG, "No elapsed time detected. Skipping CPU usage calculation.");
        return ESP_OK;
    }

    // Step 5: Detect new or deleted tasks
    bool task_found;
    ESP_LOGI(TAG, "=== Task CPU Usage Report ===");

    // Check for deleted tasks
    for (UBaseType_t x = 0; x < uxArraySizeInitial; x++) {
        task_found = false;
        for (UBaseType_t y = 0; y < uxArraySizeFinal; y++) {
            if (pxTaskStatusArrayInitial[x].xHandle == pxTaskStatusArrayFinal[y].xHandle) {
                task_found = true;
                break;
            }
        }
        if (!task_found) {
            ESP_LOGI(TAG, "Task Deleted: %s", pxTaskStatusArrayInitial[x].pcTaskName);
        }
    }

    // Check for new tasks and calculate CPU usage
    for (UBaseType_t y = 0; y < uxArraySizeFinal; y++) {
        task_found = false;
        for (UBaseType_t x = 0; x < uxArraySizeInitial; x++) {
            if (pxTaskStatusArrayFinal[y].xHandle == pxTaskStatusArrayInitial[x].xHandle) {
                task_found = true;

                // Compute CPU usage %
                uint32_t ulRunTimeDiff = pxTaskStatusArrayFinal[y].ulRunTimeCounter - pxTaskStatusArrayInitial[x].ulRunTimeCounter;
                float fCpuPercent = (float)(ulRunTimeDiff * 100.0) / (float)ulTotalElapsedTime;

                ESP_LOGI(TAG, "Task '%s' CPU Usage: %.2f%%", pxTaskStatusArrayFinal[y].pcTaskName, fCpuPercent);
                break;
            }
        }
        if (!task_found) {
            ESP_LOGI(TAG, "Task Created: %s", pxTaskStatusArrayFinal[y].pcTaskName);
        }
    }

    return ESP_OK;
}

