void AudioService::Start() {
    // Clear event flags to ensure clean start
    xEventGroupClearBits(event_group_, AS_EVENT_AUDIO_TESTING_RUNNING |
        AS_EVENT_WAKE_WORD_RUNNING |
        AS_EVENT_AUDIO_PROCESSOR_RUNNING);

    service_stopped_ = false;

    // Start the periodic power timer
    esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);

    // Create audio input task
    if (input_task_handle_ == nullptr) {
        #if CONFIG_USE_AUDIO_PROCESSOR && (CONFIG_IDF_TARGET_ESP32S3 || CONFIG_IDF_TARGET_ESP32P4)
            xTaskCreatePinnedToCore([](void* arg) {
                AudioService* service = static_cast<AudioService*>(arg);
                service->AudioInputTask();
            }, "AudioInput", 4096, this, CONFIG_AUDIO_INPUT_TASK_PRIORITY, &input_task_handle_, 1);
        #else
            xTaskCreate([](void* arg) {
                AudioService* service = static_cast<AudioService*>(arg);
                service->AudioInputTask();
            }, "AudioInput", 4096, this, CONFIG_AUDIO_INPUT_TASK_PRIORITY, &input_task_handle_);
        #endif
    }

    // Create audio output task
    if (output_task_handle_ == nullptr) {
        #if CONFIG_USE_AUDIO_PROCESSOR && (CONFIG_IDF_TARGET_ESP32S3 || CONFIG_IDF_TARGET_ESP32P4)
            xTaskCreatePinnedToCore([](void* arg) {
                AudioService* service = static_cast<AudioService*>(arg);
                service->AudioOutputTask();
            }, "AudioOutput", 4096, this, CONFIG_AUDIO_OUTPUT_TASK_PRIORITY, &output_task_handle_, 1);
        #else
            xTaskCreate([](void* arg) {
                AudioService* service = static_cast<AudioService*>(arg);
                service->AudioOutputTask();
            }, "AudioOutput", 4096, this, CONFIG_AUDIO_OUTPUT_TASK_PRIORITY, &output_task_handle_);
        #endif
    }

    // Create Opus codec task
    if (opus_task_handle_ == nullptr) {
        #if CONFIG_USE_AUDIO_PROCESSOR && (CONFIG_IDF_TARGET_ESP32S3 || CONFIG_IDF_TARGET_ESP32P4)
            xTaskCreatePinnedToCore([](void* arg) {
                AudioService* service = static_cast<AudioService*>(arg);
                service->OpusCodecTask();
            }, "OpusCodec", 4096, this, CONFIG_OPUS_CODEC_TASK_PRIORITY, &opus_task_handle_, 1);
        #else
            xTaskCreate([](void* arg) {
                AudioService* service = static_cast<AudioService*>(arg);
                service->OpusCodecTask();
            }, "OpusCodec", 4096, this, CONFIG_OPUS_CODEC_TASK_PRIORITY, &opus_task_handle_);
        #endif
    }
}

