bool AudioService::ReadAudioData(std::vector<int16_t>& data, int sample_rate, int samples) {
    // Ensure the audio input is enabled
    if (!codec_->input_enabled()) {
        esp_timer_stop(audio_power_timer_);
        esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);
        codec_->EnableInput(true);
    }

    // Update last input time for power management
    last_input_time_ = std::chrono::steady_clock::now();

    // Calculate the number of samples to read based on codec configuration
    int codec_input_samples = samples;
    if (sample_rate != codec_->input_sample_rate()) {
        // Adjust sample count for input resampling
        codec_input_samples = (int64_t)samples * codec_->input_sample_rate() / sample_rate;
    }

    // Account for channel count - we need to read enough samples for all channels
    codec_input_samples *= codec_->input_channels();

    // Resize buffer to hold raw data from codec
    std::vector<int16_t> raw_data(codec_input_samples);

    // Read data from the codec
    if (!codec_->InputData(raw_data.data(), codec_input_samples)) {
        ESP_LOGE(TAG, "Failed to read audio data from codec");
        return false;
    }

    // Update debug statistics
    debug_statistics_.capture_count++;

    // Handle channel conversion if needed
    if (codec_->input_channels() == 2) {
        // Convert stereo to mono by taking left channel only
        std::vector<int16_t> mono_data(codec_input_samples / 2);
        for (size_t i = 0, j = 0; i < mono_data.size(); ++i, j += 2) {
            mono_data[i] = raw_data[j]; // Take left channel
        }
        raw_data = std::move(mono_data);
    }

    // Handle sample rate conversion if needed
    if (codec_->input_sample_rate() != sample_rate) {
        // Use appropriate resampler based on target sample rate
        if (sample_rate == 16000) {
            int output_samples = input_resampler_.GetOutputSamples(raw_data.size());
            data.resize(output_samples);
            input_resampler_.Process(raw_data.data(), raw_data.size(), data.data());
        } else {
            // For other sample rates, we might need a different approach
            // But based on the code, 16000 seems to be the primary target
            ESP_LOGW(TAG, "Unsupported sample rate conversion: %d to %d", codec_->input_sample_rate(), sample_rate);
            data = std::move(raw_data);
        }
    } else {
        // No resampling needed
        data = std::move(raw_data);
    }

    return !data.empty();
}

