void AudioService::AudioInputTask() {
    const int kAudioFrameSamples = 16000 * OPUS_FRAME_DURATION_MS / 1000;

    while (!service_stopped_) {
        // Read audio data from microphone
        std::vector<int16_t> audio_frame;
        if (!ReadAudioData(audio_frame, 16000, kAudioFrameSamples)) {
            vTaskDelay(pdMS_TO_TICKS(10));
            continue;
        }

        // Check current system state using event group
        EventBits_t bits = xEventGroupGetBits(event_group_);

        // Route audio data based on system state
        if (bits & AS_EVENT_AUDIO_TESTING_RUNNING) {
            // Audio testing mode - push to testing queue for encoding
            PushTaskToEncodeQueue(kAudioTaskTypeEncodeToTestingQueue, std::move(audio_frame));
        } 
        else if (bits & AS_EVENT_WAKE_WORD_RUNNING) {
            // Wake word detection mode
            if (wake_word_ && wake_word_initialized_) {
                wake_word_->FeedAudioData(audio_frame);
            }
        } 
        else if (bits & AS_EVENT_AUDIO_PROCESSOR_RUNNING) {
            // General audio processing mode
            if (audio_processor_ && audio_processor_initialized_) {
                audio_processor_->FeedAudioData(audio_frame);
            }
        } 
        else {
            // Default mode - push to regular encoding queue
            PushTaskToEncodeQueue(kAudioTaskTypeEncodeToSendQueue, std::move(audio_frame));
        }
    }

    ESP_LOGW(TAG, "Audio input task stopped");
}

