void AudioService::OpusCodecTask() {
    while (true) {
        std::unique_lock<std::mutex> lock(audio_queue_mutex_);

        // Wait for either encode or decode tasks to be available
        audio_queue_cv_.wait(lock, [this]() { 
            return !audio_encode_queue_.empty() || !audio_decode_queue_.empty() || service_stopped_; 
        });

        if (service_stopped_) {
            break;
        }

        // Process encoding tasks first (PCM to Opus)
        if (!audio_encode_queue_.empty()) {
            auto task = std::move(audio_encode_queue_.front());
            audio_encode_queue_.pop_front();
            audio_queue_cv_.notify_all();
            lock.unlock();

            // Encode PCM data to Opus
            std::vector<uint8_t> encoded_data;
            if (opus_encoder_->Encode(task->pcm.data(), task->pcm.size(), encoded_data)) {
                auto packet = std::make_unique<AudioStreamPacket>();
                packet->payload = std::move(encoded_data);
                packet->sample_rate = opus_encoder_->sample_rate();
                packet->frame_duration = opus_encoder_->duration_ms();

                // Handle different task types
                switch (task->type) {
                    case kAudioTaskTypeEncodeToSendQueue:
                        {
                            std::lock_guard<std::mutex> send_lock(audio_queue_mutex_);
                            packet->timestamp = task->timestamp;
                            audio_send_queue_.push_back(std::move(packet));
                            audio_queue_cv_.notify_all();
                        }
                        break;

                    case kAudioTaskTypeEncodeToTestingQueue:
                        {
                            std::lock_guard<std::mutex> test_lock(audio_queue_mutex_);
                            if (audio_testing_queue_.size() < MAX_TESTING_PACKETS_IN_QUEUE) {
                                audio_testing_queue_.push_back(std::move(packet));
                            }
                            audio_queue_cv_.notify_all();
                        }
                        break;

                    default:
                        ESP_LOGW(TAG, "Unknown audio task type: %d", task->type);
                        break;
                }
            } else {
                ESP_LOGE(TAG, "Failed to encode audio data");
            }

            continue;
        }

        // Process decoding tasks (Opus to PCM)
        if (!audio_decode_queue_.empty()) {
            auto packet = std::move(audio_decode_queue_.front());
            audio_decode_queue_.pop_front();
            audio_queue_cv_.notify_all();
            lock.unlock();

            // Set decoder parameters if needed
            SetDecodeSampleRate(packet->sample_rate, packet->frame_duration);

            // Decode Opus data to PCM
            std::vector<int16_t> decoded_pcm;
            if (opus_decoder_->Decode(packet->payload.data(), packet->payload.size(), decoded_pcm)) {
                auto playback_task = std::make_unique<AudioPlaybackTask>();
                playback_task->timestamp = packet->timestamp;

                // Perform sample rate conversion if needed
                if (opus_decoder_->sample_rate() != codec_->output_sample_rate()) {
                    auto resampled = std::vector<int16_t>(output_resampler_.GetOutputSamples(decoded_pcm.size()));
                    output_resampler_.Process(decoded_pcm.data(), decoded_pcm.size(), resampled.data());
                    playback_task->pcm = std::move(resampled);
                } else {
                    playback_task->pcm = std::move(decoded_pcm);
                }

                // Push to playback queue
                std::unique_lock<std::mutex> playback_lock(audio_queue_mutex_);
                audio_queue_cv_.wait(playback_lock, [this]() { 
                    return audio_playback_queue_.size() < MAX_PLAYBACK_TASKS_IN_QUEUE || service_stopped_; 
                });

                if (!service_stopped_) {
                    audio_playback_queue_.push_back(std::move(playback_task));
                    audio_queue_cv_.notify_all();
                }
            } else {
                ESP_LOGE(TAG, "Failed to decode audio packet");
            }

            continue;
        }

        lock.unlock();
    }

    ESP_LOGW(TAG, "Opus codec task stopped");
}

