void AudioService::EnableWakeWordDetection(bool enable) {
    ESP_LOGD(TAG, "%s wake word detection", enable ? "Enabling" : "Disabling");

    // Check current wake word detection state and early return if already in desired state
    EventBits_t current_bits = xEventGroupGetBits(event_group_);
    bool currently_running = (current_bits & AS_EVENT_WAKE_WORD_RUNNING) != 0;

    if (enable && currently_running) {
        ESP_LOGD(TAG, "Wake word detection already enabled");
        return;
    }

    if (!enable && !currently_running) {
        ESP_LOGD(TAG, "Wake word detection already disabled");
        return;
    }

    if (enable) {
        // Initialize wake word detection system if not already initialized
        if (!wake_word_) {
            ESP_LOGE(TAG, "Wake word detection system not initialized");
            return;
        }

        // We should make sure no audio is playing
        ResetDecoder();
        audio_input_need_warmup_ = true;

        // Start the wake word detection process
        wake_word_->Start();

        // Set the corresponding event flag
        xEventGroupSetBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
    } else {
        // Stop the detection process
        if (wake_word_) {
            wake_word_->Stop();
        }

        // Clear the event flag
        xEventGroupClearBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
    }
}

