void AudioService::PlaySound(const std::string_view& ogg) {
    if (ogg.empty()) {
        ESP_LOGW(TAG, "Empty OGG data provided");
        return;
    }

    // Enable audio output if currently disabled
    if (!codec_->output_enabled()) {
        esp_timer_stop(audio_power_timer_);
        esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);
        codec_->EnableOutput(true);
    }

    // Parse OGG container and extract Opus packets
    size_t offset = 0;
    const uint8_t* data = reinterpret_cast<const uint8_t*>(ogg.data());
    size_t data_size = ogg.size();

    // Look for OGG capture pattern "OggS"
    while (offset + 27 < data_size) {
        // Check OGG page signature
        if (data[offset] == 'O' && data[offset + 1] == 'g' && 
            data[offset + 2] == 'g' && data[offset + 3] == 'S') {

            if (offset + 27 >= data_size) break;

            uint8_t header_type = data[offset + 5];
            uint32_t page_segments = data[offset + 26];

            if (offset + 27 + page_segments > data_size) break;

            // Calculate page payload start
            size_t segment_table_offset = offset + 27;
            size_t page_payload_offset = segment_table_offset + page_segments;

            // Calculate page payload size
            size_t page_payload_size = 0;
            for (uint32_t i = 0; i < page_segments; i++) {
                page_payload_size += data[segment_table_offset + i];
            }

            if (page_payload_offset + page_payload_size > data_size) break;

            // Check if this is an Opus header or data packet
            if (header_type & 0x02) { // Beginning of stream - likely contains Opus header
                // Skip header pages (typically 2 pages: identification header and comment header)
                offset = page_payload_offset + page_payload_size;
                continue;
            }

            // Extract Opus packet data
            if (page_payload_size > 0) {
                // Create audio packet for decoding
                auto packet = std::make_unique<AudioStreamPacket>();
                packet->sample_rate = 48000; // Default Opus sample rate
                packet->frame_duration = OPUS_FRAME_DURATION_MS;
                packet->payload.assign(data + page_payload_offset, data + page_payload_offset + page_payload_size);

                // Push to decode queue
                {
                    std::lock_guard<std::mutex> lock(audio_queue_mutex_);
                    if (audio_decode_queue_.size() < MAX_DECODE_PACKETS_IN_QUEUE) {
                        audio_decode_queue_.push_back(std::move(packet));
                        audio_queue_cv_.notify_all();
                    }
                }
            }

            offset = page_payload_offset + page_payload_size;
        } else {
            offset++;
        }
    }
}

