    if (models_list == nullptr) {
        return;
    }

    // Store the models list
    models_list_ = models_list;

    // Clear any existing wake word engine
    wake_word_.reset();
    wake_word_initialized_ = false;

    // Select and initialize appropriate wake word engine based on platform and model prefixes
#if CONFIG_IDF_TARGET_ESP32S3 || CONFIG_IDF_TARGET_ESP32P4
    // Check if we have AFE-compatible models
    bool has_afe_model = false;
    bool has_custom_model = false;

    for (int i = 0; i < models_list->num; i++) {
        if (strncmp(models_list->list[i].wake_word_model, "afe", 3) == 0) {
            has_afe_model = true;
        } else if (strncmp(models_list->list[i].wake_word_model, "custom", 6) == 0) {
            has_custom_model = true;
        }
    }

    // Prioritize AFE-based wake word engine if available and supported
    if (has_afe_model) {
        wake_word_ = std::make_unique<AfeWakeWord>();
    } else if (has_custom_model) {
        wake_word_ = std::make_unique<CustomWakeWord>();
