void AfeWakeWord::AudioDetectionTask() {
    while (true) {
        // Wait for detection to be enabled
        EventBits_t bits = xEventGroupWaitBits(event_group_, 
                                             DETECTION_RUNNING_EVENT,
                                             pdFALSE, 
                                             pdTRUE, 
                                             portMAX_DELAY);

        if (!(bits & DETECTION_RUNNING_EVENT)) {
            continue;
        }

        if (afe_data_ == nullptr) {
            vTaskDelay(pdMS_TO_TICKS(10));
            continue;
        }

        // Fetch processed audio data from AFE
        esp_afe_sr_state_t state = afe_iface_->fetch_result(afe_data_, (int16_t**)&afe_output_buffer_, &afe_output_size_);

        if (state == AFE_SR_STATE_WAKE_UP || state == AFE_SR_STATE_WAKEWORD_DETECT) {
            // Wake word detected
            Stop(); // Stop detection temporarily

            // Get the wake word string
            int wake_word_id = afe_iface_->get_wake_word_id(afe_data_);
            if (wake_word_id >= 0 && wake_word_id < wake_words_.size()) {
                last_detected_wake_word_ = wake_words_[wake_word_id];

                // Store the audio data leading up to and including the wake word
                StoreWakeWordData(afe_output_buffer_, afe_output_size_);

                // Trigger encoding in background task
                EncodeWakeWordData();

                // Invoke callback if registered
                if (wake_word_detected_callback_) {
                    wake_word_detected_callback_(last_detected_wake_word_);
                }
            }

            // Reset AFE buffer and resume detection
            afe_iface_->reset_buffer(afe_data_);
            Start();
        } else if (state == AFE_SR_STATE_FEED) {
            // Normal processing, store audio for potential future wake word detection
            StoreWakeWordData(afe_output_buffer_, afe_output_size_);
        }

        // Small delay to prevent busy looping
        vTaskDelay(pdMS_TO_TICKS(1));
    }
}

