void CustomWakeWord::ParseWakenetModelConfig() {
    // Clear existing commands
    commands_.clear();

    // Read the index.json file from the model directory
    const char* index_filename = "index.json";
    char* json_buffer = nullptr;
    size_t json_length = 0;

    // Try to read index.json from the model list
    if (models_ != nullptr) {
        json_buffer = (char*)esp_srmodel_get_model_buffer(models_, index_filename, &json_length);
    }

    if (json_buffer == nullptr || json_length == 0) {
        ESP_LOGE(TAG, "Failed to read index.json configuration file");
        return;
    }

    // Parse JSON
    cJSON* root = cJSON_ParseWithLength(json_buffer, json_length);
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json: invalid JSON format");
        return;
    }

    // Extract language
    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (language_item != nullptr && cJSON_IsString(language_item)) {
        language_ = language_item->valuestring;
        ESP_LOGI(TAG, "Parsed language: %s", language_.c_str());
    } else {
        language_ = "en"; // default fallback
        ESP_LOGW(TAG, "Language not specified in config, using default: %s", language_.c_str());
    }

    // Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item != nullptr && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
        ESP_LOGI(TAG, "Parsed duration: %d", duration_);
    } else {
        duration_ = 5000; // default fallback in milliseconds
        ESP_LOGW(TAG, "Duration not specified in config, using default: %d", duration_);
    }

    // Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item != nullptr && cJSON_IsNumber(threshold_item)) {
        threshold_ = (float)threshold_item->valuedouble;
        ESP_LOGI(TAG, "Parsed threshold: %.2f", threshold_);
    } else {
        threshold_ = 0.6f; // default fallback
        ESP_LOGW(TAG, "Threshold not specified in config, using default: %.2f", threshold_);
    }

    // Extract commands
    cJSON* commands_array = cJSON_GetObjectItem(root, "commands");
    if (commands_array != nullptr && cJSON_IsArray(commands_array)) {
        int commands_count = cJSON_GetArraySize(commands_array);
        ESP_LOGI(TAG, "Found %d commands in configuration", commands_count);

        for (int i = 0; i < commands_count; i++) {
            cJSON* command_obj = cJSON_GetArrayItem(commands_array, i);
            if (command_obj == nullptr) continue;

            cJSON* command_text = cJSON_GetObjectItem(command_obj, "text");
            cJSON* command_display = cJSON_GetObjectItem(command_obj, "display");
            cJSON* command_action = cJSON_GetObjectItem(command_obj, "action");

            if (command_text != nullptr && cJSON_IsString(command_text)) {
                WakeWordCommand command;
                command.command = command_text->valuestring;

                if (command_display != nullptr && cJSON_IsString(command_display)) {
                    command.text = command_display->valuestring;
                } else {
                    command.text = command.command;
                }

                if (command_action != nullptr && cJSON_IsString(command_action)) {
                    command.action = command_action->valuestring;
                } else {
                    command.action = "default";
                }

                commands_.push_back(command);
                ESP_LOGI(TAG, "Parsed command[%d]: text='%s', display='%s', action='%s'", 
                         i, command.command.c_str(), command.text.c_str(), command.action.c_str());
            }
        }
    } else {
        ESP_LOGW(TAG, "No valid commands array found in configuration");
    }

    // Cleanup
    cJSON_Delete(root);
}

