bool CustomWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models_list) {
    // Store the codec reference
    codec_ = codec;

    // Parse the wakenet model configuration from index.json
    ParseWakenetModelConfig();

    // Validate that we have a language configured
    if (language_.empty()) {
        ESP_LOGE(TAG, "No language configured for wake word detection");
        return false;
    }

    // Initialize the model list
    models_ = esp_srmodel_init(models_list);
    if (models_ == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize SR model list");
        return false;
    }

    // Find and load the appropriate multinet model based on language
    const char* model_name = esp_srmodel_filter(models_, "multinet", language_.c_str(), ESP_SR_LANG_ALL);
    if (model_name == nullptr) {
        ESP_LOGE(TAG, "Failed to find multinet model for language: %s", language_.c_str());
        return false;
    }

    ESP_LOGI(TAG, "Loading multinet model: %s", model_name);

    // Get the multinet interface
    multinet_ = esp_mn_handle(model_name);
    if (multinet_ == nullptr) {
        ESP_LOGE(TAG, "Failed to get multinet handle for model: %s", model_name);
        return false;
    }

    // Create the multinet model data
    multinet_model_data_ = multinet_->create(model_name);
    if (multinet_model_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create multinet model data for model: %s", model_name);
        return false;
    }

    // Set the detection threshold
    multinet_->set_det_threshold(multinet_model_data_, threshold_);

    // Register custom voice commands
    for (const auto& command : commands_) {
        // Command ID starts from 1 according to the Feed method logic
        int command_id = &command - &commands_[0] + 1;
        esp_mn_speech_commands_add(multinet_model_data_, command_id, command.text.c_str());
        ESP_LOGI(TAG, "Registered command %d: %s", command_id, command.text.c_str());
    }

    // Configure the audio codec
    if (codec_ != nullptr) {
        // Set codec parameters for wake word detection
        codec_->set_sample_rate(16000);  // Standard sample rate for speech recognition
        codec_->set_input_channels(1);   // Mono input for speech recognition
        codec_->set_output_channels(2);  // Stereo output (if needed)

        ESP_LOGI(TAG, "Audio codec configured for wake word detection");
    }

    ESP_LOGI(TAG, "Custom wake word detection initialized successfully");
    ESP_LOGI(TAG, "Language: %s, Threshold: %f, Commands count: %d", 
             language_.c_str(), threshold_, static_cast<int>(commands_.size()));

    return true;
}

