void CustomWakeWord::Feed(const std::vector<int16_t>& data) {
    if (!running_) {
        return;
    }

    std::vector<int16_t> mono_data;

    // Step 1: Handle stereo/mono conversion
    if (SystemInfo::GetInstance().IsStereo()) {
        // Stereo input: take every second sample (left channel)
        mono_data.reserve(data.size() / 2);
        for (size_t i = 0; i < data.size(); i += 2) {
            mono_data.push_back(data[i]);
        }
    } else {
        // Already mono
        mono_data = data;
    }

    // Step 2: Store the processed audio data
    StoreWakeWordData(mono_data);

    // Step 3: Process audio in chunks for multinet detection
    size_t feed_size = GetFeedSize();
    static std::vector<int16_t> buffer;

    // Append new data to the temporary buffer
    buffer.insert(buffer.end(), mono_data.begin(), mono_data.end());

    // Process full chunks
    while (buffer.size() >= feed_size) {
        std::vector<int16_t> chunk(buffer.begin(), buffer.begin() + feed_size);
        buffer.erase(buffer.begin(), buffer.begin() + feed_size);

        // Run detection
        int command_id = multinet_->detect(multinet_model_data_, chunk.data());

        if (command_id > 0 && command_id <= static_cast<int>(commands_.size())) {
            const std::string& detected_text = commands_[command_id - 1].display_text;

            // Trigger callback
            if (wake_word_detected_callback_) {
                wake_word_detected_callback_(detected_text);
            }

            // Deactivate further processing until restarted
            running_ = false;

            // Encode stored PCM data to Opus asynchronously
            EncodeWakeWordData();

            break; // Stop processing after detection
        }
    }
}

