std::string Board::GenerateUuid() {
    uint8_t uuid[16];

    // Step 1: Fill all 16 bytes with random data from ESP32's hardware RNG
    for (int i = 0; i < 16; ++i) {
        uuid[i] = static_cast<uint8_t>(esp_random() & 0xFF);
    }

    // Step 2: Set the UUID version to 4 (bits 4-7 of byte 6)
    uuid[6] = (uuid[6] & 0x0F) | 0x40;

    // Step 3: Set the UUID variant to RFC 4122 (bits 6-7 of byte 8 = 0b10)
    uuid[8] = (uuid[8] & 0x3F) | 0x80;

    // Step 4: Format as 36-character hyphenated hex string
    char uuid_str[37];
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

