Esp32Camera::Esp32Camera(const esp_video_init_config_t& config) {
    video_fd_ = -1;
    streaming_on_ = false;
    sensor_format_ = 0;
    sensor_width_ = 0;
    sensor_height_ = 0;

    // Initialize camera hardware with provided configuration
    esp_err_t ret = esp_video_init(&config);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize camera hardware: %s", esp_err_to_name(ret));
        return;
    }

#if CONFIG_XIAOZHI_ENABLE_CAMERA_DEBUG_MODE
    log_available_video_devices();
#endif

    // Try to open video device - search for available video devices
    for (int i = 0; i < 10; i++) {
        char path[32];
        snprintf(path, sizeof(path), "/dev/video%d", i);
        video_fd_ = open(path, O_RDWR);
        if (video_fd_ >= 0) {
            ESP_LOGI(TAG, "Opened video device: %s", path);
            break;
        }
    }

    if (video_fd_ < 0) {
        ESP_LOGE(TAG, "Failed to open video device");
        esp_video_deinit();
        return;
    }

    // Query device capabilities
    struct v4l2_capability cap = {};
    if (ioctl(video_fd_, VIDIOC_QUERYCAP, &cap) != 0) {
        ESP_LOGE(TAG, "VIDIOC_QUERYCAP failed");
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    if (!(cap.capabilities & V4L2_CAP_VIDEO_CAPTURE)) {
        ESP_LOGE(TAG, "Device does not support video capture");
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    if (!(cap.capabilities & V4L2_CAP_STREAMING)) {
        ESP_LOGE(TAG, "Device does not support streaming I/O");
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    // Enumerate and set format - try common formats
    struct v4l2_format fmt = {};
    fmt.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;

    // First try to get current format
    if (ioctl(video_fd_, VIDIOC_G_FMT, &fmt) != 0) {
        ESP_LOGW(TAG, "VIDIOC_G_FMT failed, trying to set format");

        // Try to set a default format
        fmt.fmt.pix.width = 320;
        fmt.fmt.pix.height = 240;
        fmt.fmt.pix.pixelformat = V4L2_PIX_FMT_RGB565;
        fmt.fmt.pix.field = V4L2_FIELD_ANY;

        if (ioctl(video_fd_, VIDIOC_S_FMT, &fmt) != 0) {
            ESP_LOGE(TAG, "Failed to set video format");
            close(video_fd_);
            video_fd_ = -1;
            esp_video_deinit();
            return;
        }
    }

    // Store sensor format and dimensions
    sensor_format_ = fmt.fmt.pix.pixelformat;
    sensor_width_ = fmt.fmt.pix.width;
    sensor_height_ = fmt.fmt.pix.height;

    frame_.width = sensor_width_;
    frame_.height = sensor_height_;
    frame_.format = sensor_format_;

    CAM_PRINT_FOURCC(sensor_format_);
    ESP_LOGI(TAG, "Camera initialized: %dx%d format=0x%08lx", 
             sensor_width_, sensor_height_, sensor_format_);

    // Request buffers for memory mapping
    struct v4l2_requestbuffers req = {};
    req.count = 3;
    req.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    req.memory = V4L2_MEMORY_MMAP;

    if (ioctl(video_fd_, VIDIOC_REQBUFS, &req) != 0) {
        ESP_LOGE(TAG, "VIDIOC_REQBUFS failed");
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    if (req.count < 1) {
        ESP_LOGE(TAG, "Insufficient buffer memory");
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    // Allocate buffer structures
    mmap_buffers_.resize(req.count);

    // Map the buffers
    for (size_t i = 0; i < req.count; i++) {
        struct v4l2_buffer buf = {};
        buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        buf.memory = V4L2_MEMORY_MMAP;
        buf.index = i;

        if (ioctl(video_fd_, VIDIOC_QUERYBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QUERYBUF failed for buffer %d", (int)i);
            // Cleanup already mapped buffers
            for (size_t j = 0; j < i; j++) {
                if (mmap_buffers_[j].start) {
                    munmap(mmap_buffers_[j].start, mmap_buffers_[j].length);
                }
            }
            close(video_fd_);
            video_fd_ = -1;
            esp_video_deinit();
            return;
        }

        mmap_buffers_[i].length = buf.length;
        mmap_buffers_[i].start = mmap(nullptr, buf.length, PROT_READ | PROT_WRITE, MAP_SHARED, video_fd_, buf.m.offset);

        if (mmap_buffers_[i].start == MAP_FAILED) {
            ESP_LOGE(TAG, "mmap failed for buffer %d", (int)i);
            // Cleanup already mapped buffers
            for (size_t j = 0; j < i; j++) {
                if (mmap_buffers_[j].start) {
                    munmap(mmap_buffers_[j].start, mmap_buffers_[j].length);
                }
            }
            close(video_fd_);
            video_fd_ = -1;
            esp_video_deinit();
            return;
        }
    }

    // Queue the buffers
    for (size_t i = 0; i < req.count; i++) {
        struct v4l2_buffer buf = {};
        buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        buf.memory = V4L2_MEMORY_MMAP;
        buf.index = i;

        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QBUF failed for buffer %d", (int)i);
            // Cleanup mapped buffers
            for (auto& b : mmap_buffers_) {
                if (b.start && b.length) {
                    munmap(b.start, b.length);
                }
            }
            close(video_fd_);
            video_fd_ = -1;
            esp_video_deinit();
            return;
        }
    }

    // Start streaming
    int type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    if (ioctl(video_fd_, VIDIOC_STREAMON, &type) != 0) {
        ESP_LOGE(TAG, "VIDIOC_STREAMON failed");
        // Cleanup mapped buffers
        for (auto& b : mmap_buffers_) {
            if (b.start && b.length) {
                munmap(b.start, b.length);
            }
        }
        close(video_fd_);
        video_fd_ = -1;
        esp_video_deinit();
        return;
    }

    streaming_on_ = true;
    ESP_LOGI(TAG, "Camera streaming started successfully");
}

