bool Esp32Camera::Capture() {
    // Wait for any previous encoding tasks to complete
    if (encoder_thread_.joinable()) {
        encoder_thread_.join();
    }

    // Check if camera is properly initialized
    if (video_fd_ < 0 || !streaming_on_) {
        ESP_LOGE(TAG, "Camera not properly initialized");
        return false;
    }

    // Dequeue a buffer from the camera
    struct v4l2_buffer buf = {};
    buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    buf.memory = V4L2_MEMORY_MMAP;

    // Wait for a frame to be captured
    if (ioctl(video_fd_, VIDIOC_DQBUF, &buf) != 0) {
        ESP_LOGE(TAG, "VIDIOC_DQBUF failed, errno=%d(%s)", errno, strerror(errno));
        return false;
    }

    // Validate buffer index
    if (buf.index >= mmap_buffers_.size()) {
        ESP_LOGE(TAG, "Invalid buffer index: %d", buf.index);
        // Re-queue the buffer before returning
        ioctl(video_fd_, VIDIOC_QBUF, &buf);
        return false;
    }

    // Get the buffer information
    void* src_data = mmap_buffers_[buf.index].start;
    size_t src_len = buf.bytesused;

    if (src_data == nullptr || src_len == 0) {
        ESP_LOGE(TAG, "Invalid buffer data or length");
        // Re-queue the buffer before returning
        ioctl(video_fd_, VIDIOC_QBUF, &buf);
        return false;
    }

    // Free previous frame data if exists
    if (frame_.data != nullptr) {
        heap_caps_free(frame_.data);
        frame_.data = nullptr;
        frame_.len = 0;
    }

    // Allocate memory for the frame data, prefer PSRAM
    frame_.data = (uint8_t*)heap_caps_malloc(src_len, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
    if (frame_.data == nullptr) {
        // Fallback to internal memory if PSRAM allocation fails
        frame_.data = (uint8_t*)malloc(src_len);
        if (frame_.data == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate %d bytes for frame buffer", (int)src_len);
            // Re-queue the buffer before returning
            ioctl(video_fd_, VIDIOC_QBUF, &buf);
            return false;
        }
    }

    // Copy the frame data
    memcpy(frame_.data, src_data, src_len);
    frame_.len = src_len;
    frame_.format = sensor_format_;

#ifdef CONFIG_XIAOZHI_ENABLE_ROTATE_CAMERA_IMAGE
    frame_.width = sensor_height_;   // Swapped due to rotation
    frame_.height = sensor_width_;   // Swapped due to rotation
#else
    frame_.width = buf.width;
    frame_.height = buf.height;
#endif

    // Re-queue the buffer for future captures
    if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0) {
        ESP_LOGE(TAG, "VIDIOC_QBUF failed, errno=%d(%s)", errno, strerror(errno));
        // Clean up allocated memory
        heap_caps_free(frame_.data);
        frame_.data = nullptr;
        frame_.len = 0;
        return false;
    }

    ESP_LOGD(TAG, "Captured frame: %dx%d, format=0x%08lx, size=%d bytes", 
             frame_.width, frame_.height, frame_.format, (int)frame_.len);

    return true;
}

