std::string Esp32Camera::Explain(const std::string& question) {
    // First capture the image
    if (!Capture()) {
        return "{\"success\": false, \"message\": \"Failed to capture image\"}";
    }

    // Check if we have a valid frame
    if (!frame_.data || frame_.len == 0) {
        return "{\"success\": false, \"message\": \"No image data captured\"}";
    }

    // Check if explain URL is set
    if (explain_url_.empty()) {
        return "{\"success\": false, \"message\": \"Explain URL not set\"}";
    }

    // Wait for any previous encoder thread to finish
    if (encoder_thread_.joinable()) {
        encoder_thread_.join();
    }

    // Create a queue for JPEG chunks
    jpeg_chunk_queue_ = xQueueCreate(10, sizeof(JpegChunk));
    if (jpeg_chunk_queue_ == NULL) {
        return "{\"success\": false, \"message\": \"Failed to create JPEG chunk queue\"}";
    }

    // Flag to indicate encoding completion
    volatile bool encoding_complete = false;
    std::string result = "";

    // Start JPEG encoding in a separate thread
    encoder_thread_ = std::thread([this, &encoding_complete]() {
        // Encode the frame to JPEG
        uint8_t* jpeg_data = nullptr;
        size_t jpeg_len = 0;

        esp_err_t ret = image_to_jpeg(
            frame_.data, 
            frame_.width, 
            frame_.height, 
            static_cast<pixel_format_t>(frame_.format),
            &jpeg_data, 
            &jpeg_len
        );

        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to encode image to JPEG: %s", esp_err_to_name(ret));
            encoding_complete = true;
            return;
        }

        // Split JPEG data into chunks and send to queue
        const size_t chunk_size = 4096;
        size_t sent = 0;

        while (sent < jpeg_len) {
            size_t remaining = jpeg_len - sent;
            size_t current_chunk_size = (remaining > chunk_size) ? chunk_size : remaining;

            JpegChunk chunk;
            chunk.data = (uint8_t*)malloc(current_chunk_size);
            if (!chunk.data) {
                ESP_LOGE(TAG, "Failed to allocate memory for JPEG chunk");
                break;
            }

            memcpy(chunk.data, jpeg_data + sent, current_chunk_size);
            chunk.size = current_chunk_size;
            chunk.is_last = (sent + current_chunk_size >= jpeg_len);

            // Send chunk to queue
            if (xQueueSend(jpeg_chunk_queue_, &chunk, portMAX_DELAY) != pdTRUE) {
                ESP_LOGE(TAG, "Failed to send JPEG chunk to queue");
                free(chunk.data);
                break;
            }

            sent += current_chunk_size;
        }

        // Free the original JPEG data
        if (jpeg_data) {
            free(jpeg_data);
        }

        encoding_complete = true;
    });

    // Prepare HTTP client and headers
    esp_http_client_config_t config = {};
    config.url = explain_url_.c_str();
    config.method = HTTP_METHOD_POST;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        if (encoder_thread_.joinable()) {
            encoder_thread_.join();
        }
        vQueueDelete(jpeg_chunk_queue_);
        return "{\"success\": false, \"message\": \"Failed to initialize HTTP client\"}";
    }

    // Set headers
    esp_http_client_set_header(client, "Content-Type", "multipart/form-data; boundary=----Esp32CameraBoundary");

    // Add device identification
    std::string device_id = SystemInfo::GetDeviceId();
    if (!device_id.empty()) {
        esp_http_client_set_header(client, "X-Device-ID", device_id.c_str());
    }

    // Add client ID
    std::string client_id = SystemInfo::GetClientId();
    if (!client_id.empty()) {
        esp_http_client_set_header(client, "X-Client-ID", client_id.c_str());
    }

    // Add authentication token
    if (!explain_token_.empty()) {
        std::string auth_header = "Bearer " + explain_token_;
        esp_http_client_set_header(client, "Authorization", auth_header.c_str());
    }

    // Perform HTTP POST request
    esp_err_t err = esp_http_client_open(client, 0); // 0 means chunked transfer
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        if (encoder_thread_.joinable()) {
            encoder_thread_.join();
        }
        vQueueDelete(jpeg_chunk_queue_);
        return "{\"success\": false, \"message\": \"Failed to open HTTP connection\"}";
    }

    // Send multipart form data
    std::string boundary = "------Esp32CameraBoundary";
    std::string contentDisposition = "Content-Disposition: form-data; name=\"image\"; filename=\"image.jpg\"";
    std::string contentType = "Content-Type: image/jpeg";
    std::string questionDisposition = "Content-Disposition: form-data; name=\"question\"";

    // Send question field
    std::string questionPart = boundary + "\r\n" + 
                              questionDisposition + "\r\n" +
                              "Content-Type: text/plain\r\n\r\n" +
                              question + "\r\n";
    esp_http_client_write(client, questionPart.c_str(), questionPart.length());

    // Send image field header
    std::string imageHeader = boundary + "\r\n" +
                             contentDisposition + "\r\n" +
                             contentType + "\r\n\r\n";
    esp_http_client_write(client, imageHeader.c_str(), imageHeader.length());

    // Receive and send JPEG chunks
    bool transfer_success = true;
    while (!encoding_complete || uxQueueMessagesWaiting(jpeg_chunk_queue_) > 0) {
        JpegChunk chunk;
        if (xQueueReceive(jpeg_chunk_queue_, &chunk, pdMS_TO_TICKS(1000)) == pdTRUE) {
            int written = esp_http_client_write(client, (char*)chunk.data, chunk.size);
            if (written != (int)chunk.size) {
                ESP_LOGE(TAG, "Failed to write complete JPEG chunk");
                transfer_success = false;
            }
            free(chunk.data);
        }
    }

    // Send closing boundary
    std::string closingBoundary = "\r\n" + boundary + "--\r\n";
    esp_http_client_write(client, closingBoundary.c_str(), closingBoundary.length());

    // Wait for encoder thread to complete
    if (encoder_thread_.joinable()) {
        encoder_thread_.join();
    }

    // Clean up queue
    vQueueDelete(jpeg_chunk_queue_);

    // Get response
    if (transfer_success) {
        int status_code = esp_http_client_fetch_headers(client);
        if (status_code == 200) {
            char response_buffer[2048];
            int read_len = esp_http_client_read(client, response_buffer, sizeof(response_buffer) - 1);
            if (read_len > 0) {
                response_buffer[read_len] = '\0';
                result = std::string(response_buffer);
            } else {
                result = "{\"success\": true, \"message\": \"Request sent successfully, but no response content\"}";
            }
        } else {
            char error_msg[256];
            snprintf(error_msg, sizeof(error_msg), "{\"success\": false, \"message\": \"HTTP error %d\"}", status_code);
            result = std::string(error_msg);
        }
    } else {
        result = "{\"success\": false, \"message\": \"Failed to transfer image data\"}";
    }

    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    return result;
}

