void WifiBoard::StartNetwork() {
    ESP_LOGI(TAG, "Starting WiFi network");

    // Initialize WiFi manager with predefined SSID prefix and language settings
    auto& wifi_manager = WifiManager::GetInstance();
    auto& ssid_manager = SsidManager::GetInstance();

    // Set up unified event callback for handling WiFi state transitions
    wifi_manager.SetEventCallback([this](NetworkEvent event, const std::string& data) {
        this->OnNetworkEvent(event, data);
    });

    // Initialize SSID manager with device name from settings
    Settings settings("wifi");
    std::string device_name = settings.GetString("device_name", "ESP32_Device");
    ssid_manager.Initialize(device_name);

    // Attempt to establish WiFi connection using saved credentials
    TryWifiConnect();
}

