void WifiBoard::StartWifiConfigMode() {
    ESP_LOGI(TAG, "Starting WiFi configuration mode");

    // Set device state to configuring mode
    auto& app = Application::GetInstance();
    app.SetDeviceState(kDeviceStateConfiguring);

    // Provide initial user feedback
    GetDisplay()->ShowNotification(Lang::Strings::WIFI_CONFIG_MODE_STARTED);

    // Select and start appropriate provisioning method based on compile-time flags
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Use Bluetooth Low Energy provisioning via Blufi
    ESP_LOGI(TAG, "Starting Blufi provisioning");
    GetDisplay()->ShowNotification(Lang::Strings::BLUFI_PROVISIONING_ACTIVE);
    Blufi::GetInstance().init();

#elif defined(CONFIG_USE_ACOUSTIC_PROVISIONING)
