LcdDisplay::~LcdDisplay() {
    // Stop and delete the GIF controller
    if (gif_controller_) {
        gif_controller_->Stop();
        gif_controller_.reset();
    }

    // Delete the preview image timer
    if (preview_timer_) {
        esp_timer_stop(preview_timer_);
        esp_timer_delete(preview_timer_);
        preview_timer_ = nullptr;
    }

    // Clean up UI elements by deleting the main container which should cascade delete children
    if (container_) {
        lv_obj_del(container_);
        container_ = nullptr;
    }

    // Explicitly clean up any remaining UI elements that might not be children of container
    if (top_bar_) {
        lv_obj_del(top_bar_);
        top_bar_ = nullptr;
