    // Center text in bubble
    lv_obj_center(message_text);

    // Manage message history - remove oldest messages if exceeding MAX_MESSAGES
    uint32_t child_count = lv_obj_get_child_cnt(content_);
    while (child_count > MAX_MESSAGES) {
        lv_obj_t* oldest_message = lv_obj_get_child(content_, 0);
        if (oldest_message != nullptr) {
            lv_obj_del(oldest_message);
        }
        child_count = lv_obj_get_child_cnt(content_);
    }

    // Scroll to the new message
    lv_obj_scroll_to_view_recursive(is_system_message || strcmp(role, "user") == 0 ? message_container : message_bubble, LV_ANIM_ON);
}

