void LcdDisplay::SetPreviewImage(std::unique_ptr<LvglImage> image)
{
    DisplayLockGuard lock(this);

    // Handle null image case - hide preview and show emoji
    if (image == nullptr) {
        esp_timer_stop(preview_timer_);
        lv_obj_remove_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
        lv_obj_add_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);
        preview_image_cached_.reset();
        if (gif_controller_) {
            gif_controller_->Start();
        }
        return;
    }

    // Cache the image
    preview_image_cached_ = std::move(image);
    auto img_dsc = preview_image_cached_->image_dsc();

    // Validate image dimensions
    if (img_dsc->header.w <= 0 || img_dsc->header.h <= 0) {
        ESP_LOGW(TAG, "Invalid image dimensions: %d x %d, using default size", 
                 img_dsc->header.w, img_dsc->header.h);
        // Use default sizing - half of screen dimensions
        img_dsc->header.w = width_ / 2;
        img_dsc->header.h = height_ / 2;
    }

    // Define maximum dimensions for preview (85% of screen)
    const lv_coord_t max_width = LV_HOR_RES * 85 / 100;
    const lv_coord_t max_height = LV_VER_RES * 85 / 100;

    // Calculate scaled dimensions maintaining aspect ratio
    lv_coord_t scaled_width = img_dsc->header.w;
    lv_coord_t scaled_height = img_dsc->header.h;

    if (scaled_width > max_width) {
        scaled_height = (scaled_height * max_width) / scaled_width;
        scaled_width = max_width;
    }

    if (scaled_height > max_height) {
        scaled_width = (scaled_width * max_height) / scaled_height;
        scaled_height = max_height;
    }

    // Ensure we have minimum size
    if (scaled_width < 20) scaled_width = 20;
    if (scaled_height < 20) scaled_height = 20;

    // Create a styled message bubble container for the preview
    if (chat_message_label_ != nullptr) {
        // Remove previous preview bubble if exists
        lv_obj_t* parent = lv_obj_get_parent(chat_message_label_);
        if (parent != content_) {
            lv_obj_del(parent);
        }
    }

    auto lvgl_theme = static_cast<LvglTheme*>(current_theme_);

    // Create a full-width container for the image preview
    lv_obj_t* msg_container = lv_obj_create(content_);
    lv_obj_set_width(msg_container, LV_HOR_RES);
    lv_obj_set_height(msg_container, LV_SIZE_CONTENT);
    lv_obj_set_style_bg_opa(msg_container, LV_OPA_TRANSP, 0);
    lv_obj_set_style_border_width(msg_container, 0, 0);
    lv_obj_set_style_pad_all(msg_container, 0, 0);

    // Create the image bubble
    lv_obj_t* image_bubble = lv_obj_create(msg_container);
    lv_obj_set_style_radius(image_bubble, 8, 0);
    lv_obj_set_scrollbar_mode(image_bubble, LV_SCROLLBAR_MODE_OFF);
    lv_obj_set_style_border_width(image_bubble, 0, 0);
    lv_obj_set_style_pad_all(image_bubble, lvgl_theme->spacing(2), 0);
    lv_obj_set_style_bg_color(image_bubble, lvgl_theme->system_bubble_color(), 0);
    lv_obj_set_style_bg_opa(image_bubble, LV_OPA_70, 0);

    // Set custom attribute to mark bubble type
    lv_obj_set_user_data(image_bubble, (void*)"image");

    // Create image object inside the bubble
    lv_obj_t* preview_img = lv_image_create(image_bubble);
    lv_image_set_src(preview_img, img_dsc);

    // Set the size of the image and bubble
    lv_obj_set_width(preview_img, scaled_width);
    lv_obj_set_height(preview_img, scaled_height);
    lv_obj_set_width(image_bubble, scaled_width + lvgl_theme->spacing(4));
    lv_obj_set_height(image_bubble, scaled_height + lvgl_theme->spacing(4));

    // Center the image in the bubble
    lv_obj_center(preview_img);

    // Center the bubble in the container
    lv_obj_align(image_bubble, LV_ALIGN_CENTER, 0, 0);

    // Store reference to the image
    chat_message_label_ = preview_img;

    // Stop any GIF animation
    if (gif_controller_) {
        gif_controller_->Stop();
    }

    // Hide emoji box and show preview
    lv_obj_add_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
    lv_obj_remove_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);

    // Start the timer to automatically hide the preview
    esp_timer_stop(preview_timer_);
    ESP_ERROR_CHECK(esp_timer_start_once(preview_timer_, PREVIEW_IMAGE_DURATION_MS * 1000));

    // Scroll to view the new image preview
    lv_obj_scroll_to_view_recursive(msg_container, LV_ANIM_ON);
}

