void LcdDisplay::SetPreviewImage(std::unique_ptr<LvglImage> image) {
    DisplayLockGuard lock(this);

    // Stop any existing preview timer
    esp_timer_stop(preview_timer_);

    // If image is null, clean up and restore normal state
    if (image == nullptr) {
        if (preview_image_ != nullptr) {
            lv_obj_del(preview_image_);
            preview_image_ = nullptr;
        }
        preview_image_cached_.reset();

        // Resume GIF animation if it was paused
        if (gif_controller_) {
            gif_controller_->Start();
        }
        return;
    }

    // Cache the image
    preview_image_cached_ = std::move(image);
    auto img_dsc = preview_image_cached_->image_dsc();

    // Validate image dimensions
    int img_width = img_dsc->header.w;
    int img_height = img_dsc->header.h;

    // Handle invalid dimensions with default sizing
    if (img_width <= 0 || img_height <= 0) {
        ESP_LOGW(TAG, "Invalid image dimensions (%d x %d), using default size", img_width, img_height);
        img_width = 200;   // Default width
        img_height = 150;  // Default height
    }

    // Define maximum dimensions for preview
    const int max_width = LV_HOR_RES * 85 / 100;   // 85% of screen width
    const int max_height = LV_VER_RES * 60 / 100;  // 60% of screen height

    // Calculate scaled dimensions while maintaining aspect ratio
    int scaled_width = img_width;
    int scaled_height = img_height;

    if (scaled_width > max_width) {
        float ratio = (float)max_width / scaled_width;
        scaled_width = max_width;
        scaled_height = (int)(scaled_height * ratio);
    }

    if (scaled_height > max_height) {
        float ratio = (float)max_height / scaled_height;
        scaled_height = max_height;
        scaled_width = (int)(scaled_width * ratio);
    }

    // Ensure minimum size
    if (scaled_width < 50) scaled_width = 50;
    if (scaled_height < 50) scaled_height = 50;

    // Pause any running GIF animation
    if (gif_controller_) {
        gif_controller_->Stop();
    }

    // Remove existing preview image object if it exists
    if (preview_image_ != nullptr) {
        lv_obj_del(preview_image_);
        preview_image_ = nullptr;
    }

    // Create a message bubble container for the image preview
    auto lvgl_theme = static_cast<LvglTheme*>(current_theme_);

    // Create bubble container
    lv_obj_t* image_bubble = lv_obj_create(content_);
    lv_obj_set_style_radius(image_bubble, 8, 0);
    lv_obj_set_scrollbar_mode(image_bubble, LV_SCROLLBAR_MODE_OFF);
    lv_obj_set_style_border_width(image_bubble, 0, 0);
    lv_obj_set_style_pad_all(image_bubble, lvgl_theme->spacing(4), 0);
    lv_obj_set_style_bg_color(image_bubble, lvgl_theme->system_bubble_color(), 0);
    lv_obj_set_style_bg_opa(image_bubble, LV_OPA_70, 0);

    // Set bubble size
    lv_obj_set_width(image_bubble, scaled_width + lvgl_theme->spacing(8));
    lv_obj_set_height(image_bubble, scaled_height + lvgl_theme->spacing(8));

    // Set custom attribute to mark bubble type
    lv_obj_set_user_data(image_bubble, (void*)"image");

    // Create the image object inside the bubble
    preview_image_ = lv_image_create(image_bubble);
    lv_image_set_src(preview_image_, img_dsc);

    // Set image size
    lv_obj_set_width(preview_image_, scaled_width);
    lv_obj_set_height(preview_image_, scaled_height);

    // Center the image in the bubble
    lv_obj_center(preview_image_);

    // Auto-scroll to the image bubble
    lv_obj_scroll_to_view_recursive(image_bubble, LV_ANIM_ON);

    // Start the preview timer to automatically hide the image
    ESP_ERROR_CHECK(esp_timer_start_once(preview_timer_, PREVIEW_IMAGE_DURATION_MS * 1000));
}

