void LcdDisplay::SetChatMessage(const char* role, const char* content) {
    DisplayLockGuard lock(this);

    // Validate input parameters
    if (content_ == nullptr || role == nullptr || content == nullptr) {
        return;
    }

    // Filter out empty messages
    if (strlen(content) == 0) {
        return;
    }

    auto lvgl_theme = static_cast<LvglTheme*>(current_theme_);
    auto text_font = lvgl_theme->text_font()->font();

    // Check if this is a system message
    bool is_system_message = (strcmp(role, "system") == 0);

    // Hide AI logo for non-system messages
    if (!is_system_message && emoji_label_ != nullptr) {
        lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
    }

    // Create message bubble container
    lv_obj_t* message_container = nullptr;
    lv_obj_t* message_bubble = nullptr;

    if (is_system_message) {
        // System messages: full width, centered
        message_container = lv_obj_create(content_);
        lv_obj_set_width(message_container, LV_PCT(100));
        lv_obj_set_style_pad_hor(message_container, 0, 0);
        lv_obj_set_style_pad_ver(message_container, lvgl_theme->spacing(2), 0);
        lv_obj_set_style_bg_opa(message_container, LV_OPA_TRANSP, 0);
