        lv_obj_set_style_bg_color(message_bubble, lvgl_theme->system_bubble_color(), 0);
        lv_obj_set_style_border_color(message_bubble, lvgl_theme->border_color(), 0);
        lv_obj_set_style_border_width(message_bubble, 1, 0);
        lv_obj_set_style_pad_all(message_bubble, lvgl_theme->spacing(3), 0);
        lv_obj_set_style_margin_hor(message_bubble, lvgl_theme->spacing(4), 0);
        lv_obj_set_style_margin_ver(message_bubble, 0, 0);
        lv_obj_set_width(message_bubble, LV_SIZE_CONTENT);
        lv_obj_set_style_max_width(message_bubble, LV_PCT(80), 0);
        lv_obj_center(message_bubble);

        // Mark bubble type for theme updates
        lv_obj_set_user_data(message_bubble, (void*)"system");
    } else {
        bool is_user_message = (strcmp(role, "user") == 0);

        if (is_user_message) {
            // User messages: right aligned
            message_container = lv_obj_create(content_);
            lv_obj_set_width(message_container, LV_PCT(100));
            lv_obj_set_style_pad_hor(message_container, 0, 0);
            lv_obj_set_style_pad_ver(message_container, 0, 0);
            lv_obj_set_style_bg_opa(message_container, LV_OPA_TRANSP, 0);
            lv_obj_set_style_border_width(message_container, 0, 0);

            message_bubble = lv_obj_create(message_container);
            lv_obj_set_style_radius(message_bubble, lvgl_theme->spacing(4), 0);
            lv_obj_set_style_bg_color(message_bubble, lvgl_theme->user_bubble_color(), 0);
            lv_obj_set_style_border_color(message_bubble, lvgl_theme->border_color(), 0);
            lv_obj_set_style_border_width(message_bubble, 1, 0);
            lv_obj_set_style_pad_all(message_bubble, lvgl_theme->spacing(3), 0);
            lv_obj_set_style_margin_left(message_bubble, LV_PCT(20), 0);
            lv_obj_set_style_margin_right(message_bubble, lvgl_theme->spacing(4), 0);
            lv_obj_set_style_margin_top(message_bubble, 0, 0);
            lv_obj_set_style_margin_bottom(message_bubble, 0, 0);
            lv_obj_align(message_bubble, LV_ALIGN_RIGHT_MID, 0, 0);

            // Mark bubble type for theme updates
            lv_obj_set_user_data(message_bubble, (void*)"user");
        } else {
            // Assistant messages: left aligned (default)
            message_bubble = lv_obj_create(content_);
            lv_obj_set_style_radius(message_bubble, lvgl_theme->spacing(4), 0);
            lv_obj_set_style_bg_color(message_bubble, lvgl_theme->assistant_bubble_color(), 0);
            lv_obj_set_style_border_color(message_bubble, lvgl_theme->border_color(), 0);
            lv_obj_set_style_border_width(message_bubble, 1, 0);
            lv_obj_set_style_pad_all(message_bubble, lvgl_theme->spacing(3), 0);
            lv_obj_set_style_margin_right(message_bubble, LV_PCT(20), 0);
            lv_obj_set_style_margin_left(message_bubble, lvgl_theme->spacing(4), 0);
            lv_obj_set_style_margin_top(message_bubble, 0, 0);
            lv_obj_set_style_margin_bottom(message_bubble, 0, 0);
            lv_obj_align(message_bubble, LV_ALIGN_LEFT_MID, 0, 0);

            // Mark bubble type for theme updates
            lv_obj_set_user_data(message_bubble, (void*)"assistant");
        }
    }

    // Create text label inside the bubble
    lv_obj_t* message_text = lv_label_create(is_system_message || strcmp(role, "user") == 0 ? message_bubble : message_bubble);
    lv_label_set_text(message_text, content);
    lv_obj_set_width(message_text, LV_SIZE_CONTENT);
    lv_label_set_long_mode(message_text, LV_LABEL_LONG_WRAP);

    // Set text color based on message type
    if (is_system_message) {
        lv_obj_set_style_text_color(message_text, lvgl_theme->system_text_color(), 0);
    } else {
        lv_obj_set_style_text_color(message_text, lvgl_theme->text_color(), 0);
    }

    // Center text in bubble
    lv_obj_center(message_text);

    // Manage message history - remove oldest messages if exceeding MAX_MESSAGES
    uint32_t child_count = lv_obj_get_child_cnt(content_);
    while (child_count > MAX_MESSAGES) {
        lv_obj_t* oldest_message = lv_obj_get_child(content_, 0);
        if (oldest_message != nullptr) {
            lv_obj_del(oldest_message);
        }
        child_count = lv_obj_get_child_cnt(content_);
    }

    // Scroll to the new message
    lv_obj_scroll_to_view_recursive(is_system_message || strcmp(role, "user") == 0 ? message_container : message_bubble, LV_ANIM_ON);
}

