void SingleLed::OnStateChanged() {
    DeviceState state = GetDeviceState();

    switch (state) {
        case kDeviceStateStarting:
            // Blue color, slow blink - system booting up
            SetColor(0, 0, HIGH_BRIGHTNESS);
            StartContinuousBlink(1000);
            break;

        case kDeviceStateWifiConfiguring:
            // Yellow/Orange color, fast blink - waiting for WiFi setup
            SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS / 2, 0);
            StartContinuousBlink(200);
            break;

        case kDeviceStateIdle:
            // Green color, steady on - ready and waiting
            SetColor(0, HIGH_BRIGHTNESS, 0);
            TurnOn();
            break;

        case kDeviceStateConnecting:
            // Blue color, medium blink - attempting network connection
            SetColor(0, 0, HIGH_BRIGHTNESS);
            StartContinuousBlink(500);
            break;

        case kDeviceStateListening:
            // Cyan color, steady on - actively listening for voice input
            SetColor(0, HIGH_BRIGHTNESS, HIGH_BRIGHTNESS);
            TurnOn();
            break;

        case kDeviceStateSpeaking:
            // Purple color, pulse effect - speaking response
            SetColor(HIGH_BRIGHTNESS, 0, HIGH_BRIGHTNESS);
            StartContinuousBlink(300);
            break;

        case kDeviceStateUpgrading:
            // White color, very fast blink - firmware upgrade in progress
            SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS, HIGH_BRIGHTNESS);
            StartContinuousBlink(100);
            break;

        case kDeviceStateActivating:
            // Rainbow effect simulation - activation process
            SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS / 2, 0);
            StartContinuousBlink(150);
            break;

        case kDeviceStateError:
            // Red color, slow blink - error state
            SetColor(HIGH_BRIGHTNESS, 0, 0);
            StartContinuousBlink(1000);
            break;

        case kDeviceStateUnknown:
        default:
            // Off or dim white - unknown state
            SetColor(LOW_BRIGHTNESS, LOW_BRIGHTNESS, LOW_BRIGHTNESS);
            TurnOn();
            break;
    }
}

