bool WebsocketProtocol::OpenAudioChannel() {
    // Reset error state
    error_occurred_ = false;

    // Get system information for authentication
    auto device_id = SystemInfo::GetDeviceId();
    auto auth_token = Settings::GetAuthToken();

    // Create WebSocket client with configuration
    websocket_ = std::make_unique<WebSocket>();

    // Configure authentication headers
    websocket_->SetHeader("Authorization", "Bearer " + auth_token);
    websocket_->SetHeader("X-Device-ID", device_id);

    // Set protocol version (assuming version_ is already set or needs to be determined)
    if (version_ == 0) {
        version_ = 3; // Default to latest version
    }

    // Configure WebSocket URL (assuming it's defined somewhere or needs to be constructed)
    std::string ws_url = Settings::GetServerUrl();
    if (ws_url.empty()) {
        ws_url = "wss://default-server.com/audio";
    }

    // Add audio channel endpoint
    if (ws_url.back() != '/') {
        ws_url += "/";
    }
    ws_url += "audio";

    // Set binary protocol subprotocol
    if (version_ == 2) {
        websocket_->SetSubprotocol("audio.binary.v2");
    } else if (version_ == 3) {
        websocket_->SetSubprotocol("audio.binary.v3");
    } else {
        websocket_->SetSubprotocol("audio.binary");
    }

    // Set up data handler for incoming messages
    websocket_->OnData([this](const uint8_t* data, size_t len, bool is_text) {
        if (is_text) {
            // Handle text messages (JSON)
            if (on_incoming_json_ && len > 0) {
                std::string json_str(reinterpret_cast<const char*>(data), len);
                cJSON* root = cJSON_Parse(json_str.c_str());
                if (root) {
                    if (cJSON_GetObjectItem(root, "type")) {
                        std::string msg_type = cJSON_GetObjectItem(root, "type")->valuestring;
                        if (msg_type == "hello") {
                            ParseServerHello(root);
                        }
                    }
                    on_incoming_json_(root);
                    cJSON_Delete(root);
                }
            }
        } else {
            // Handle binary audio data
            if (on_incoming_audio_ && len > 0) {
                std::unique_ptr<AudioStreamPacket> packet = std::make_unique<AudioStreamPacket>();

                if (version_ == 2 && len >= sizeof(BinaryProtocol2)) {
                    // Parse BinaryProtocol v2
                    const BinaryProtocol2* bp2 = reinterpret_cast<const BinaryProtocol2*>(data);
                    uint16_t version = ntohs(bp2->version);
                    if (version == 2) {
                        packet->timestamp = ntohl(bp2->timestamp);
                        uint32_t payload_size = ntohl(bp2->payload_size);
                        if (sizeof(BinaryProtocol2) + payload_size <= len) {
                            packet->payload.assign(bp2->payload, bp2->payload + payload_size);
                            packet->sample_rate = server_sample_rate_;
                            packet->frame_duration = server_frame_duration_;
                            on_incoming_audio_(std::move(packet));
                        }
                    }
                } else if (version_ == 3 && len >= sizeof(BinaryProtocol3)) {
                    // Parse BinaryProtocol v3
                    const BinaryProtocol3* bp3 = reinterpret_cast<const BinaryProtocol3*>(data);
                    uint16_t payload_size = ntohs(bp3->payload_size);
                    if (sizeof(BinaryProtocol3) + payload_size <= len) {
                        packet->payload.assign(bp3->payload, bp3->payload + payload_size);
                        packet->sample_rate = server_sample_rate_;
                        packet->frame_duration = server_frame_duration_;
                        on_incoming_audio_(std::move(packet));
                    }
                } else {
                    // Raw audio data
                    packet->payload.assign(data, data + len);
                    packet->sample_rate = server_sample_rate_;
                    packet->frame_duration = server_frame_duration_;
                    on_incoming_audio_(std::move(packet));
                }
            }
        }
    });

    // Set connection handlers
    websocket_->OnConnected([this]() {
        if (on_connected_) {
            on_connected_();
        }

        // Send hello message after connection
        std::string hello_msg = GetHelloMessage();
        websocket_->Send(hello_msg);
    });

    websocket_->OnDisconnected([this]() {
        if (on_disconnected_) {
            on_disconnected_();
        }
    });

    websocket_->OnError([this](const std::string& error) {
        ESP_LOGE(TAG, "WebSocket error: %s", error.c_str());
        SetError(error);
        if (on_network_error_) {
            on_network_error_(error);
        }
    });

    // Establish WebSocket connection
    if (!websocket_->Connect(ws_url)) {
        ESP_LOGE(TAG, "Failed to connect to WebSocket server");
        websocket_.reset();
        return false;
    }

    return true;
}

