void WebsocketProtocol::ParseServerHello(const cJSON* root) {
    if (root == nullptr) {
        ESP_LOGE(TAG, "Invalid server hello message: null root");
        return;
    }

    // Validate transport type
    const cJSON* transport_item = cJSON_GetObjectItem(root, "transport");
    if (transport_item == nullptr || !cJSON_IsString(transport_item)) {
        ESP_LOGE(TAG, "Missing or invalid 'transport' field in server hello");
        return;
    }

    if (strcmp(transport_item->valuestring, "websocket") != 0) {
        ESP_LOGE(TAG, "Unsupported transport type: %s", transport_item->valuestring);
        return;
    }

    // Optional session_id extraction
    const cJSON* session_id_item = cJSON_GetObjectItem(root, "session_id");
    if (session_id_item != nullptr && cJSON_IsString(session_id_item)) {
        session_id_ = session_id_item->valuestring;
        ESP_LOGI(TAG, "Session ID received: %s", session_id_.c_str());
