        return;
    }

    const cJSON* sample_rate_item = cJSON_GetObjectItem(audio_params, "sample_rate");
    const cJSON* frame_duration_item = cJSON_GetObjectItem(audio_params, "frame_duration");

    if (sample_rate_item == nullptr || !cJSON_IsNumber(sample_rate_item)) {
        ESP_LOGE(TAG, "Missing or invalid 'sample_rate' in audio_params");
        return;
